// C.O.D.E. Atlas -- Knowledge Explorer UI
let W=document.querySelector('#workspace');const D=document.querySelector('#detail-content'),shell=document.querySelector('.shell');let cases=[],atlasSession={};
if(location.pathname==='/graph')document.body.classList.add('graph-page');
window.addEventListener('error',function(e){if(W&&W.querySelector&&W.querySelector('.loading'))W.innerHTML='<div class="error"><h2>Atlas workspace failed to load</h2><p>Stage: JavaScript initialization</p><p>'+esc(e.message||'Runtime error')+'</p><button class="button-sm" onclick="location.reload()">Retry</button></div>'});
window.addEventListener('unhandledrejection',function(e){console.error('Unhandled Atlas promise rejection',e.reason);if(W&&W.querySelector&&W.querySelector('.loading'))W.innerHTML='<div class="error"><h2>Atlas workspace failed to load</h2><p>Stage: asynchronous initialization</p><p>'+esc(e.reason&&e.reason.message||'Unexpected request failure')+'</p><button class="button-sm" onclick="location.reload()">Retry</button></div>'});
const esc=s=>String(s===null||s===undefined?'':s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const ATLAS_PRODUCT_DEFINITION="以机制证据档案为核心，连接研究问题、文献证据、实验上下文、证据分歧、知识图谱与人工审核的生物医学证据工作台。";
const WORKSPACE_NAV_BASE=[["探索 Discover","/discover"],["证据地图 Graph","/graph"],["收藏与报告 Library","/library"]];
const LEGACY_CONFLICT_REVIEW_LABELS=["Correctly Rejected","Should Be Weak","Mech Split Useful","Valid Weak","Valid Context Split","Invalid/Non-comp"];
try{localStorage.removeItem("atlas_mode")}catch(e){}
let atlasMode="standard",allowedAtlasModes=["standard","professional"],allowedWorkspaces=["discover","library"],debugAccess=false;
function getAtlasMode(){return atlasMode}
function isPharmaMode(){return true}
function isReviewerMode(){return canReview()&&!canDeveloper()}
function isDeveloperMode(){return debugAccess}
function canReview(){return allowedWorkspaces.indexOf("review")>=0}
function canDeveloper(){return allowedWorkspaces.indexOf("console")>=0||debugAccess}
function isModeAllowed(mode){return mode==="standard"||mode==="professional"||(mode==="technical"&&canDeveloper())}
function firstAllowedMode(){return"standard"}
function enforceAllowedMode(){if(!isModeAllowed(atlasMode))atlasMode="standard"}
function configureAllowedModes(modes){allowedAtlasModes=["standard","professional"].concat(debugAccess?["technical"]:[]);enforceAllowedMode();applyAtlasMode()}
function configureSessionCapabilities(session){allowedWorkspaces=session.allowed_workspaces||["discover","library"];debugAccess=!!session.debug_access;configureAllowedModes()}
function workspaceAllowed(key){return allowedWorkspaces.indexOf(key)>=0}
function renderModeNav(){var nav=document.querySelector("nav");if(!nav)return;var p=location.pathname||"/",items=WORKSPACE_NAV_BASE.slice();if(workspaceAllowed("review"))items.splice(1,0,["审核 Review","/review"],["仲裁 Adjudication","/adjudication"]);if(workspaceAllowed("console"))items.push(["开发者控制台 Console","/console"]);if(workspaceAllowed("owner"))items.push(["Owner","/owner"]);items.push(["帮助","/help"]);nav.innerHTML='<p class="nav-label">ATLAS</p>'+items.map(function(x){var active=p===x[1]||(x[1]!=="/"&&p.indexOf(x[1])===0)||((p==="/"||p==="/cases"||p.indexOf("/case/")===0||p.indexOf("/dossier/")===0||p==="/evidence")&&x[1]==="/discover")||(p==="/dev"&&x[1]==="/console");return'<a href="'+x[1]+'" class="'+(active?'active':'')+'">'+esc(x[0])+'</a>'}).join("")}
function applyAtlasMode(){enforceAllowedMode();document.body.dataset.atlasMode="standard";document.querySelectorAll(".mode-switch").forEach(function(x){x.remove()});renderModeNav()}
function setAtlasMode(mode){atlasMode=isModeAllowed(mode)?mode:"standard";applyAtlasMode();closePanel();route()}
function initModeSwitch(){applyAtlasMode()}
function modeHelp(){return'<div id="mode-help" class="mode-help">'+esc(ATLAS_PRODUCT_DEFINITION)+'</div>'}
function modeBanner(){return'<div class="mode-banner"><div><span class="mode-kicker">C.O.D.E. Atlas</span><strong>机制证据档案工作台</strong><p>'+esc(ATLAS_PRODUCT_DEFINITION)+'</p></div></div>'}
function humanizeRelation(rel,direction){var r=String(rel||direction||"unknown").toLowerCase().replace(/[\s-]+/g,"_");if(/promot|increase|activat|upregulat|positive/.test(r))return"促进 / 上调 / 激活";if(/inhibit|decrease|suppress|downregulat|negative/.test(r))return"抑制 / 下调";if(/associated|correlat/.test(r))return"相关";if(/regulat|affect|modulat/.test(r))return"调节 / 影响";return"影响"}
function humanizeDirection(direction){var d=String(direction||"").toLowerCase();if(/positive|up|increase|promote|activate/.test(d))return"正向";if(/negative|down|decrease|inhibit|suppress/.test(d))return"负向";return d||"未说明"}
function humanizeEntityType(type){var t=String(type||"").toLowerCase();if(t==="gene"||t==="protein"||t==="gene/protein")return"基因/蛋白";if(t==="compound"||t==="drug"||t==="compound/drug")return"药物/化合物";if(t==="pathway")return"通路";if(t==="biological_process")return"生物过程";if(t==="disease")return"疾病";if(t==="phenotype"||t==="clinical_outcome")return"表型/临床结局";if(t==="cell_type"||t==="tissue")return"细胞/组织";return type||"实体"}
function shortId(id){id=String(id||"");return id.length>14?id.slice(0,6)+"..."+id.slice(-6):id}
function renderMechanismExplanation(x){var subj=x.subject_display_label||x.subject_label||x.subject||"Subject",obj=x.object_display_label||x.object_label||x.object||"Object",rel=x.relation_normalized||x.relation||"affects",ctx=x.context||x.context_text||x.section_title||"当前证据";return"这条关系表示：在 "+esc(ctx)+" 条件下，"+esc(subj)+" 可能会"+esc(humanizeRelation(rel,x.direction))+" "+esc(obj)+"。"}
function renderMechanismStatement(x){var subj=x.subject_display_label||x.subject_label||x.subject||"研究对象",obj=x.object_display_label||x.object_label||x.object||"结果",rel=x.relation_normalized||x.relation||"affects";return esc(subj)+" <span class=\"edge\">"+esc(humanizeRelation(rel,x.direction))+"</span> "+esc(obj)}
function renderContextSummary(x){var ctx=x.context||x.context_text||x.section_title||"";if(typeof ctx==="object")ctx=Object.entries(ctx).filter(function(p){return p[1]}).map(function(p){return p[0]+": "+p[1]}).join(" · ");return ctx?esc(ctx):"当前证据未提供结构化实验条件。"}
function renderEvidenceStatus(x){var bits=[];if((x.fulltext_evidence_count||x.case_fulltext_evidence_count||0)>0)bits.push("全文支持");else bits.push("仅摘要/间接支持");if(x.review_status==="reviewed"||(x.annotation&&x.annotation.final_label))bits.push("已审核");else bits.push("待审核");if(x.conflict_status&&x.conflict_status!=="none")bits.push("可能存在条件差异");return bits.map(function(b){return'<span class="badge">'+esc(b)+'</span>'}).join("")}
function dossierIdOf(x){return x.dossier_id||x.public_id||x.triple_id||""}
function dossierHref(x){return'/dossier/'+encodeURIComponent(dossierIdOf(x))}
function renderMechanismEvidenceUnit(x){var subj=(x.subject&&x.subject.label)||x.subject_display_label||x.subject_label||x.subject,obj=(x.object&&x.object.label)||x.object_display_label||x.object_label||x.object,rel=(x.relation&&x.relation.normalized)||x.relation_normalized||x.relation,ev=x.evidence_summary||{};return'<article class="card mechanism-unit"><div class="pharma-label">机制证据档案</div><h3>'+esc(x.humanized_statement||'')+(x.humanized_statement?'':(esc(subj)+' <span class="edge">'+esc(humanizeRelation(rel,x.direction))+'</span> '+esc(obj)))+'</h3><h4>这意味着什么</h4><p>'+renderMechanismExplanation({subject_display_label:subj,object_display_label:obj,relation_normalized:rel,direction:x.direction})+'</p><h4>证据状态</h4><p><span class="badge">证据 '+esc(ev.total||x.evidence_count||x.case_evidence_count||0)+'</span><span class="badge">全文 '+esc(ev.fulltext_count||x.fulltext_evidence_count||x.case_fulltext_evidence_count||0)+'</span>'+((x.badges||[]).map(function(b){return'<span class="badge">'+esc(b)+'</span>'}).join(''))+'</p><details class="professional-details"><summary>查看专业详情</summary><p class="meta">相关研究问题：'+esc((x.related_cases||x.case_ids||[x.case_id]).filter(Boolean).join(", ")||"未指定")+'</p></details><div class="toolbar"><a class="button-sm" href="'+dossierHref(x)+'">打开机制档案</a><button class="button-sm" data-library-save="dossier" data-library-id="'+esc(dossierIdOf(x))+'" data-library-label="'+esc(x.humanized_statement||subj+' '+rel+' '+obj)+'">收藏</button>'+(canReview()?'<a class="button-sm" href="/review">进入审核任务</a>':'')+'</div>'+renderDeveloperDetails(x,"Developer details")+'</article>'}
function renderDeveloperDetails(obj,title){if(!isDeveloperMode())return"";obj=obj||{};var raw=JSON.stringify(obj,null,2),keys=["case_id","entity_id","triple_id","chain_id","review_item_id","source_file","source_line","bundle_path","display_priority_score","noise_risk_score"],buttons=keys.filter(function(k){return obj[k]!==undefined&&obj[k]!==null&&obj[k]!==""}).map(function(k){return'<button class="button-sm copy-btn" data-copy-text="'+esc(obj[k])+'">Copy '+esc(k)+'</button>'});buttons.push('<button class="button-sm copy-btn" data-copy-text="'+esc(raw)+'">Copy raw JSON</button>');return'<details class="developer-details" open><summary>'+esc(title||"Developer details")+'</summary><div class="developer-copy-row">'+buttons.join("")+'</div><pre>'+esc(raw)+'</pre></details>'}
function asItems(payload){if(Array.isArray(payload))return payload;if(payload&&Array.isArray(payload.items))return payload.items;if(payload&&Array.isArray(payload.records))return payload.records;if(payload&&Array.isArray(payload.chains))return payload.chains;if(payload&&Array.isArray(payload.triples))return payload.triples;return[]}
function asSummary(payload){if(payload&&typeof payload.summary==='object')return payload.summary;return{}}
function ensureDict(v){if(v&&typeof v==='object'&&!Array.isArray(v))return v;return{}}
function ensureArray(v){return Array.isArray(v)?v:[]}
function showPageError(containerId,title,err,retry){var el=document.querySelector(containerId);if(el)el.innerHTML='<div class="error" role="alert"><h3>'+esc(title||'Page Error')+'</h3><p>'+esc(err&&err.message||'Unknown error')+'</p>'+(err&&err.endpoint?'<p class="meta">'+esc(err.endpoint)+(err.status?' · HTTP '+esc(err.status):'')+'</p>':'')+(retry?'<button class="button-sm" onclick="'+retry+'">Retry</button>':'')+'</div>'}
async function atlasRequest(path,options){options=options||{};var controller=typeof AbortController==='function'?new AbortController():null,timer=controller?setTimeout(function(){controller.abort()},15000):null,r,textBody,d;try{r=await fetch(path,Object.assign({},options,controller?{signal:controller.signal}:{}))}catch(cause){var networkError=Error(cause&&cause.name==='AbortError'?'Request timed out':'Network request failed');networkError.endpoint=path;networkError.cause=cause;throw networkError}finally{if(timer)clearTimeout(timer)}try{if(typeof r.text==='function'){textBody=await r.text();d=textBody?JSON.parse(textBody):{}}else{d=await r.json()}}catch(cause){var parseError=Error('Invalid server response');parseError.endpoint=path;parseError.status=r.status;parseError.cause=cause;throw parseError}if(!r.ok){var e=Error(d.error||('HTTP '+r.status));e.endpoint=path;e.status=r.status;e.code=d.error;e.field_errors=d.field_errors;e.payload=d;if(r.status===401&&location.pathname!=='/login')location.href='/login?next='+encodeURIComponent(location.pathname+location.search);throw e}return d}
async function api(path){return atlasRequest(path)}
async function apiPost(path,body){return atlasRequest(path,{method:'POST',headers:{'Content-Type':'application/json','X-CSRF-Token':atlasSession.csrf_token||''},body:JSON.stringify(body||{})})}
function showToast(msg,type){let t=document.createElement('div');t.className='toast toast-'+(type||'info');t.setAttribute('role','status');t.setAttribute('aria-live','polite');t.textContent=msg;document.body.appendChild(t);requestAnimationFrame(function(){t.classList.add('show')});setTimeout(function(){t.classList.remove('show');setTimeout(function(){t.remove()},400)},2500)}
function fallbackCopyText(text){var textarea=document.createElement("textarea");textarea.value=text;textarea.setAttribute("readonly","");textarea.style.position="fixed";textarea.style.left="-9999px";textarea.style.top="0";document.body.appendChild(textarea);textarea.focus();textarea.select();textarea.setSelectionRange(0,text.length);var ok=document.execCommand&&document.execCommand("copy");document.body.removeChild(textarea);if(!ok)throw Error("copy command unavailable")}
async function copyTextToClipboard(text,btn){text=String(text||"");if(!text){showToast("没有可复制的内容","warn");return false}try{if(typeof navigator!=="undefined"&&navigator.clipboard&&typeof window!=="undefined"&&window.isSecureContext){try{await navigator.clipboard.writeText(text)}catch(clipboardErr){fallbackCopyText(text)}}else{fallbackCopyText(text)}showToast("已复制","success");if(btn){var old=btn.textContent;btn.textContent="已复制";btn.classList.add("copied");setTimeout(function(){btn.textContent=old;btn.classList.remove("copied")},1200)}return true}catch(err){console.error("Copy failed",err);showToast("复制失败，请手动选择文本复制","error");return false}}
function openTriplePanel(){shell.classList.add('panel-open')}
function closePanel(){shell.classList.remove('panel-open');_activeTripleId=null;document.querySelectorAll('.triple-row.selected-row').forEach(function(r){r.classList.remove('selected-row')})}
function openTriple(id){if(!id)return;openTriplePanel();_activeTripleId=id;D.innerHTML='<div class="loading">Loading triple evidence…</div>';api('/api/triple/'+encodeURIComponent(id)+'?evidence_limit=50').then(function(t){var header=isPharmaMode()?'<div class="evidence-detail-header pharma-card"><div class="pharma-label">机制关系</div><h2>'+esc(t.subject_display_label)+' <span class="edge">'+esc(humanizeRelation(t.relation_normalized,t.direction))+'</span> '+esc(t.object_display_label)+'</h2><p>'+renderMechanismExplanation(t)+'</p></div>':'<div class="evidence-detail-header"><h2>'+esc(t.subject_display_label)+' <span class="edge">'+esc(t.relation_normalized)+'</span> '+esc(t.object_display_label)+'</h2>'+badges(t.ui_badges)+'</div>';var debug=isDeveloperMode()?'<h4>Validator Annotations</h4>'+((t.validator_annotations||[]).map(function(v){return'<div class="card"><b>'+esc(v.validator_name)+'</b> · '+esc(v.status)+'<p class="muted">'+esc(v.summary)+'</p>'+renderDeveloperDetails(v,"Validator details")+'</div>'}).join('')||'<div class="empty">None</div>')+'<h4>Conflict Lens</h4>'+((t.conflict_lens_records||[]).map(function(c){return'<div class="card"><span class="badge conflict">'+esc(c.record_type)+'</span><p>'+esc(c.rejection_reason||'Triage record')+'</p>'+renderDeveloperDetails(c,"Conflict record")+'</div>'}).join('')||'<div class="empty">None</div>')+renderDeveloperDetails(t,"Triple raw / debug"):'';D.innerHTML=header+'<p class="meta">'+(t.evidence_total||0)+' evidence · '+(t.fulltext_evidence_count||0)+' fulltext <span class="developer-only">· Cases: '+esc((t.case_ids||[]).join(', '))+'</span></p><div class="toolbar evidence-filter-bar"><button class="button-sm evidence-filter-btn active" onclick="filterEvidence(\x27\x27)">All</button><button class="button-sm evidence-filter-btn" onclick="filterEvidence(\x27fulltext\x27)">Fulltext</button><button class="button-sm evidence-filter-btn" onclick="filterEvidence(\x27results\x27)">Results</button></div><div id="evidence-list">'+evidenceHtml(t.evidence_links)+'</div>'+debug;}).catch(function(e){D.innerHTML='<div class="error">Failed to load triple: '+esc(e.message)+'</div>'})}
const badges=a=>(a||[]).map(function(x){return'<span class="badge">'+esc(x.replaceAll('_',' '))+'</span>'}).join('');
function renderPharmaMechanismCard(x){var subj=x.subject_display_label||x.subject_label||x.subject,obj=x.object_display_label||x.object_label||x.object,rel=x.relation_normalized||x.relation||"affects";return'<article class="card clickable mechanism-card" onclick="location.href=\''+dossierHref(x)+'\'"><div class="pharma-label">机制证据档案</div><div class="triple"><span class="entity">'+esc(subj)+'</span><span class="edge">'+esc(humanizeRelation(rel,x.direction))+'</span><span class="entity">'+esc(obj)+'</span></div><p>'+renderMechanismExplanation(x)+'</p><p class="meta">'+(x.evidence_count||x.case_evidence_count||0)+' 条证据 · '+(x.fulltext_evidence_count||x.case_fulltext_evidence_count||0)+' 条全文证据</p><div class="pharma-judgment-lite"><span>请判断：</span><button>支持</button><button>部分支持</button><button>不支持</button><button>证据不足</button></div>'+renderDeveloperDetails(x)+'</article>'}
function tripleCard(x){if(isPharmaMode())return renderPharmaMechanismCard(x);return'<article class="card clickable" onclick="openTriple(\''+esc(x.triple_id)+'\')"><div class="triple"><span class="entity">'+esc(x.subject_display_label||x.subject_label)+'</span><span class="edge">'+esc(x.relation_normalized)+'</span><span class="entity">'+esc(x.object_display_label||x.object_label)+'</span></div><p class="meta">'+(x.evidence_count||x.case_evidence_count||0)+' evidence \xb7 '+(x.fulltext_evidence_count||x.case_fulltext_evidence_count||0)+' fulltext <span class="developer-only">\xb7 '+esc(shortId(x.triple_id))+'</span></p>'+badges(x.ui_badges)+renderDeveloperDetails(x)+'</article>'}
function chainCard(x){var nodes=x.entity_path||[],rels=x.relation_path||[],html='',eb=[];if((x.fulltext_evidence_count_sum||0)>0)eb.push('<span class="badge">'+(isPharmaMode()?'全文证据':'fulltext')+'</span>');if((x.results_section_evidence_count_sum||0)>0)eb.push('<span class="badge">Results</span>');if(x.conflict_statuses&&x.conflict_statuses.length>0)eb.push('<span class="badge conflict">'+(isPharmaMode()?'冲突线索':'conflict lens')+'</span>');for(var i=0;i<nodes.length;i++){html+='<span class="chain-entity" title="'+esc(nodes[i])+'">'+esc(nodes[i])+'</span>';if(i<rels.length){html+='<span class="chain-relation-arrow">→</span><span class="chain-relation">'+esc(rels[i])+'</span><span class="chain-relation-arrow">→</span>'}}return'<article class="card clickable chain-path-card" onclick="openChain(\''+esc(x.chain_id)+'\')"><div class="chain-path">'+html+'</div><div class="chain-meta"><p class="meta">'+(isPharmaMode()?('包含 '+(x.depth||(x.triple_ids||[]).length)+' 条机制关系 · '+(x.fulltext_evidence_count_sum||x.case_fulltext_evidence_count_sum||0)+' 条全文证据'):('Depth '+(x.depth||(x.triple_ids||[]).length)+' · '+(x.fulltext_evidence_count_sum||x.case_fulltext_evidence_count_sum||0)+' fulltext evidence'))+'</p>'+eb.join('')+'</div>'+renderDeveloperDetails(x)+'</article>'}
function title(t,s){renderModeNav();W.innerHTML=modeBanner()+'<div class="hero"><h1>'+esc(t||'')+'</h1><p>'+esc(s||'')+'</p>'+modeHelp()+'</div>'}
function renderEvidenceReadingCard(e){var s=e.review_status||'not_in_review_queue',lb='';if(e.annotation&&e.annotation.final_label)lb='<span class="badge review-label-badge label-'+e.annotation.final_label.toLowerCase()+'">'+esc(e.annotation.final_label)+'</span>';var ab=e.review_item_id?' <button class="button-sm reviewer-only" onclick="openReviewItemDirect(\''+encodeURIComponent(e.review_item_id)+'\')">Annotate</button>':' <span class="muted reviewer-only">Not in review queue</span>';var evidenceText=e.evidence_sentence||e.claim_text||'';return'<div class="evidence evidence-reading-card"><span class="badge reviewer-only">'+esc(e.source_scope||'source unknown')+'</span><span class="badge">'+esc(e.section_title||'section unknown')+'</span>'+(e.paper_title?'<span class="badge type">'+esc(e.paper_title)+'</span>':'')+'<blockquote>'+esc(e.evidence_sentence||e.claim_text||'No text preview')+'</blockquote><p class="meta">'+(isPharmaMode()?'机制关系：':'Extracted relation: ')+esc(e.extracted_relation||e.relation||'not provided')+' · '+(isPharmaMode()?'证据语境：':'Context: ')+esc(e.context||e.context_text||'not provided')+'</p><p class="meta">PMID '+esc(e.pmid||'\u2014')+' · PMCID '+esc(e.pmcid||'\u2014')+'</p><div class="pharma-judgment-lite pharma-only"><span>请判断：</span><button>支持</button><button>部分支持</button><button>不支持</button><button>不确定</button></div><div class="reviewer-only"><span class="badge '+(s==='reviewed'?'':'warn')+'">'+esc(s.replaceAll('_',' '))+'</span>'+lb+ab+'</div><button class="button-sm copy-btn" data-copy-text="'+esc(evidenceText)+'">'+(isPharmaMode()?'复制证据':'Copy evidence')+'</button>'+renderDeveloperDetails(e)+'</div>'}
function evidenceHtml(a){return(a||[]).map(function(e){if(!isDeveloperMode())return renderEvidenceReadingCard(e);var s=e.review_status||'not_in_review_queue',lb='',evidenceText=e.evidence_sentence||e.claim_text||'';if(e.annotation&&e.annotation.final_label)lb='<span class="badge review-label-badge label-'+e.annotation.final_label.toLowerCase()+'">'+esc(e.annotation.final_label)+'</span>';var ab=e.review_item_id?' <button class="button-sm" onclick="openReviewItemDirect(\''+encodeURIComponent(e.review_item_id)+'\')">Annotate</button>':' <span class="muted">Not in review queue</span>';return'<div class="evidence"><span class="badge">'+esc(e.source_scope)+'</span><span class="badge '+(s==='reviewed'?'':'warn')+'">'+esc(s.replaceAll('_',' '))+'</span>'+lb+'<span class="badge">'+esc(e.section_title||'section unknown')+'</span><blockquote>'+esc(e.evidence_sentence||e.claim_text||'No text preview')+'</blockquote><p class="meta">PMID '+esc(e.pmid||'\u2014')+' \xb7 '+esc(e.case_id)+' \xb7 '+esc(e.source_file)+':'+e.source_line+'</p><button class="button-sm copy-btn" data-copy-text="'+esc(evidenceText)+'">Copy evidence</button>'+ab+renderDeveloperDetails(e)+'</div>'}).join('')||'<div class="empty">No evidence for this filter.</div>'}
async function home(){var s=await api('/api/summary');if(isPharmaMode()){title('C.O.D.E. Atlas 药学阅读模式','你需要做的事：选择一个研究问题，阅读系统提出的机制线索，查看证据原文，判断证据是否支持该机制。');W.innerHTML+='<div class="reader-steps"><b>你需要做的事</b><ol><li>选择一个研究问题</li><li>阅读系统提出的机制线索</li><li>查看证据原文</li><li>判断证据是否支持该机制</li></ol></div><div class="grid"><div class="card metric"><strong>'+s.cases+'</strong>研究问题</div><div class="card metric"><strong>'+s.display_triples+'</strong>机制关系</div><div class="card metric"><strong>'+s.fulltext_evidence_count+'</strong>全文证据</div><div class="card metric"><strong>'+s.review_queue_count+'</strong>需要人工判断</div></div><h2>选择研究问题</h2><div class="grid">'+cases.map(function(c){return'<a class="card clickable pharma-card" href="/case/'+encodeURIComponent(c.case_id)+'"><h3>'+esc(c.case_id.replaceAll("_"," "))+'</h3><p>阅读该研究问题下的机制线索和证据。</p><p class="meta">研究问题 / 机制线索 / 证据 / 待审核</p></a>'}).join('')+'</div>';return}if(isReviewerMode()){title('数据审核员工作台','默认入口是审核任务：选择 case 和 item type，阅读 evidence sentence，选择 VALID / PARTIAL / INVALID / UNCLEAR，然后保存。');W.innerHTML+='<div class="review-home-actions"><a class="button review-primary-action" href="/review">进入审核任务</a><a class="button" href="/metrics">查看审核进度</a><a class="button" href="/api/review-export.csv">导出 CSV</a><a class="button" href="/api/review-export.jsonl">导出 JSONL</a></div><div class="grid"><div class="card metric"><strong>'+s.review_queue_count+'</strong>审核队列</div><div class="card metric"><strong>'+s.cases+'</strong>当前 case</div><div class="card metric"><strong>'+s.fulltext_evidence_count+'</strong>证据句来源</div><div class="card metric"><strong>'+s.conflict_lens_records+'</strong>冲突/诊断项</div></div><div class="review-workbench-card reviewer-landing"><b>审核目标：</b> 确认系统抽取的 subject / relation / object / direction / context 是否被 evidence sentence 支持。快捷键 V/P/I/U/S 可用于判断和保存。</div>';return}title('Developer Debug Console','Pipeline / artifact debugging workspace with full IDs, source provenance, raw JSON, display KG and review diagnostics.');W.innerHTML+='<div class="grid">'+[['Cases',s.cases],['Display entities',s.display_entities],['Display triples',s.display_triples],['Candidate chains',s.display_chains],['Fulltext evidence',s.fulltext_evidence_count],['Conflict records',s.conflict_lens_records],['Review queue',s.review_queue_count]].map(function(x){return'<div class="card metric developer-metric"><strong>'+x[1]+'</strong>'+x[0]+'</div>'}).join('')+'</div><h2>Debug entry points</h2><div class="grid">'+[['Cases / bundle paths','Case-focused KG and provenance','/cases'],['Entities','Display KG entity records','/entities'],['Triples','Display KG triples and evidence links','/triples'],['Chains','Clean KG chain candidates','/chains'],['Conflicts','Validator and conflict lens records','/conflicts'],['Review','Annotation queue API surface','/review'],['Debug metrics','Review metrics JSON view','/metrics']].map(function(x){return'<a class="card clickable developer-card" href="'+x[2]+'"><h3>'+x[0]+'</h3><p class="muted">'+x[1]+'</p></a>'}).join('')+'</div>'+(s.warnings||[]).map(function(x){return'<p class="badge warn">'+esc(x)+'</p>'}).join('')}
