async function progressWorkspace(){if(!canReview()){W.innerHTML='<div class="error">Forbidden</div>';return}var m=await api('/api/review-metrics'),a=await api('/api/annotations');var user=(atlasSession.user||{}).username||'';var mine=(a.items||[]).filter(function(x){return !user||x.reviewer_id===user||x.reviewer_id==='local_user'});title('我的进度','当前为本地审核统计；如果 reviewer_id 与登录名不一致，个人统计可能退化为本地汇总。');W.innerHTML+='<div class="grid"><div class="card metric"><strong>'+mine.length+'</strong>已审核数量</div><div class="card metric"><strong>'+m.unreviewed_count+'</strong>待审核数量</div><div class="card metric"><strong>'+Object.entries(m.counts_by_final_label||{}).map(function(p){return p[0]+': '+p[1]}).join(' / ')+'</strong>VALID / PARTIAL / INVALID / UNCLEAR</div></div><h2>按 case 统计</h2><div class="grid">'+Object.entries(m.counts_by_case||{}).map(function(p){return'<div class="card"><h3>'+esc(p[0])+'</h3><p class="meta">已审核 '+p[1]+'</p></div>'}).join('')+'</div><h2>最近审核记录</h2><div class="list">'+mine.slice(-20).reverse().map(function(x){return'<div class="card"><span class="badge">'+esc(x.final_label||'')+'</span><h3>'+esc(x.review_item_id||'')+'</h3><p class="meta">'+esc(x.notes||'')+'</p></div>'}).join('')+'</div>'}
async function devWorkspace(){if(!canDeveloper()){W.innerHTML='<div class="error">Forbidden</div>';return}title('Developer Console','System A handoff、ingestion、artifact validation、projection、Schema 与 capability diagnostics。科研治理和盲审答案不在此工作台。');var d=await api('/api/console/overview'),p=d.projection||{},caps=d.capabilities||[],failures=d.sync_failures||[];W.innerHTML+='<section class="readiness-hero '+(p.validation_status==='valid'?'is-ready':'is-blocked')+'"><span class="eyebrow">Projection health</span><h2>'+esc(p.validation_status||'unknown')+'</h2><p>'+esc(p.projection_id||'No current projection')+' · '+esc(p.schema_version||'schema unknown')+' · '+esc(p.adapter_version||'adapter unknown')+'</p></section><div class="metric-grid"><div class="card metric"><strong>'+esc((d.handoff_sources||[]).length)+'</strong>handoffs</div><div class="card metric"><strong>'+esc(caps.length)+'</strong>case capabilities</div><div class="card metric"><strong>'+esc(failures.length)+'</strong>sync failures</div><div class="card metric"><strong>'+esc((d.database||{}).schema_version||'n/a')+'</strong>DB schema</div></div><div class="dev-grid"><section class="card developer-console"><h2>Projection / Schema</h2><pre>'+esc(JSON.stringify(p,null,2))+'</pre></section><section class="card developer-console"><h2>Capability effectiveness</h2><pre>'+esc(JSON.stringify(caps,null,2))+'</pre></section><section class="card developer-console"><h2>Sync failures</h2><pre>'+esc(JSON.stringify(failures,null,2))+'</pre></section><section class="card"><h2>权限边界</h2><p>blind_review_payload_included: '+esc(d.blind_review_payload_included)+'</p><p>Developer 无用户管理、任务分配、仲裁提交、Gold freeze 或 Production metrics 权限。</p></section></div>'+renderDeveloperDetails(d,'Technical diagnostics raw')}
