async function searchView(){var q=new URLSearchParams(location.search).get('q')||'';title('全局搜索','按研究问题、机制证据档案、实体、文献和机制路径分组。');var d=q?await api('/api/search?q='+encodeURIComponent(q)):{cases:[],dossiers:[],entities:[],papers:[],paths:[]};W.innerHTML+='<div class="toolbar"><input id="search-q" aria-label="全局搜索" placeholder="搜索药物、基因、蛋白、通路、疾病、研究问题或 PMID" value="'+esc(q)+'"><button class="button" onclick="location.href=\'/search?q=\'+encodeURIComponent(document.querySelector(\'#search-q\').value)">搜索</button></div>'+renderSearchGroup('研究问题',d.cases,function(x){return'<a class="card clickable" href="/case/'+encodeURIComponent(x.case_id)+'"><h3>'+esc(x.case_id)+'</h3><p class="meta">'+esc(x.display_triples_count||0)+' 个机制档案</p></a>'})+renderSearchGroup('机制证据档案',d.dossiers,renderMechanismEvidenceUnit)+renderSearchGroup('实体',d.entities,function(x){return'<a class="card clickable" href="/entity/'+encodeURIComponent(x.entity_id)+'"><h3>'+esc(x.display_label||x.label)+'</h3><p class="meta">'+esc(humanizeEntityType(x.entity_type))+'</p></a>'})+renderSearchGroup('文献',d.papers,function(x){return'<div class="card"><h3>'+esc(x.paper_title||x.pmid||x.pmcid||'文献')+'</h3><blockquote>'+esc(x.evidence_sentence||'')+'</blockquote><p class="meta">PMID '+esc(x.pmid||'未报告')+' · PMCID '+esc(x.pmcid||'未报告')+'</p></div>'})+renderSearchGroup('机制路径',d.paths,function(x){return'<a class="card clickable" href="/chain/'+encodeURIComponent(x.chain_id)+'">'+chainPathVisual(x)+'</a>'})}
async function dossierView(id){var d=await api('/api/dossier/'+encodeURIComponent(id));rememberRecent({id:d.dossier_id,label:d.humanized_statement,href:'/dossier/'+encodeURIComponent(d.dossier_id)});title(d.humanized_statement,'机制证据档案：概览、支持证据、条件差异、上下文矩阵、相关路径、来源与审核。');var ev=await api('/api/dossier/'+encodeURIComponent(d.dossier_id)+'/evidence'),ctx=await api('/api/dossier/'+encodeURIComponent(d.dossier_id)+'/context-matrix'),paths=await api('/api/dossier/'+encodeURIComponent(d.dossier_id)+'/paths'),rt=await api('/api/dossier/'+encodeURIComponent(d.dossier_id)+'/review-target');W.innerHTML+='<div class="dossier-layout"><section class="card dossier-overview"><h2>概览</h2><div class="metric-grid">'+[['证据数量',d.summary.evidence_count],['全文覆盖',d.summary.fulltext_coverage],['摘要证据',d.summary.abstract_coverage],['涉及文献',d.summary.paper_count],['涉及研究问题',d.summary.case_count],['证据一致性',d.summary.evidence_consistency],['人工审核',d.summary.review_status]].map(function(x){return'<div class="card metric"><strong>'+esc(x[1])+'</strong>'+esc(x[0])+'</div>'}).join('')+'</div><p>'+renderMechanismExplanation({subject_display_label:d.subject.label,object_display_label:d.object.label,relation_normalized:d.relation.normalized})+'</p><div class="toolbar"><button class="button-sm" data-library-save="dossier" data-library-id="'+esc(d.dossier_id)+'" data-library-label="'+esc(d.humanized_statement)+'">收藏机制</button>'+(rt.reviewable?'<a class="button-sm" href="/review#'+encodeURIComponent(rt.review_item_id)+'">进入审核</a>':'<span class="badge warn">暂无匹配审核任务</span>')+'</div>'+renderDeveloperDetails(d,"Dossier raw / debug")+'</section><section><h2>支持证据</h2>'+renderEvidenceGroups(ev.groups)+'</section><section><h2>分歧与条件差异</h2>'+renderConflictSummaryBlock(d.conflict_summary)+'</section><section><h2>上下文矩阵</h2>'+renderContextMatrix(ctx)+'</section><section><h2>相关机制路径</h2>'+renderDossierPaths(paths.items)+'</section><section><h2>来源与审核</h2><div class="card"><p>相关研究问题：'+esc((d.related_cases||[]).join(', ')||'未报告')+'</p><p>审核状态：'+esc((d.review_summary||{}).label||'未报告')+'</p></div></section></div>'}
function renderEvidenceGroups(groups){return['supporting','opposing_or_differing','uncertain'].map(function(k){var label={supporting:'支持证据',opposing_or_differing:'分歧或条件不同',uncertain:'不确定'}[k];return'<h3>'+label+'</h3><div class="list">'+((groups[k]||[]).map(renderEvidenceDossierCard).join('')||'<div class="empty">暂无记录。</div>')+'</div>'}).join('')}
function renderEvidenceDossierCard(e){var classLabel={supporting:'支持该机制',opposing_or_differing:'条件不同或存在分歧',uncertain:'需要人工判断'}[e.evidence_class]||'需要人工判断';return'<div class="evidence evidence-reading-card"><span class="badge">'+esc(classLabel)+'</span><span class="badge">'+esc(e.source_scope||'未报告')+'</span><span class="badge">'+esc(e.section||e.section_title||'未报告')+'</span><blockquote>'+esc(e.evidence_sentence||'当前数据只包含证据句。')+'</blockquote><p>系统抽取：'+esc((e.extracted||{}).subject||'')+' '+esc((e.extracted||{}).relation||'')+' '+esc((e.extracted||{}).object||'')+'</p><p class="meta">PMID '+esc(e.pmid||'未报告')+' · PMCID '+esc(e.pmcid||'未报告')+'</p><details class="professional-details"><summary>分类依据</summary><p class="meta">'+esc(e.classification_reason||'未报告')+'</p></details>'+renderDeveloperDetails(e)+'</div>'}
function renderConflictSummaryBlock(c){return'<div class="card"><span class="badge conflict">'+esc(c.label||'证据不足')+'</span><p>记录数：'+esc(c.count||0)+'</p>'+renderDeveloperDetails(c,"Conflict technical details")+'</div>'}
function renderContextMatrix(ctx){var labels={paper_title:'文献',pmid:'PMID',pmcid:'PMCID',case_id:'研究问题',source_scope:'证据来源',section_title:'论文部分',species:'物种',cell_type:'细胞类型',tissue:'组织',disease_or_cancer_type:'疾病/癌种',treatment:'处理',dose:'剂量',time:'时间',genotype:'基因型',localization:'定位',direction:'方向',evidence_class:'证据分类',classification_reason:'分类依据'};var cols=ctx.columns||[],rows=ctx.items||[];return'<div class="context-matrix-wrap" tabindex="0"><table class="context-matrix"><thead><tr>'+cols.map(function(c){return'<th>'+esc(labels[c]||c.replaceAll("_"," "))+'</th>'}).join('')+'</tr></thead><tbody>'+rows.map(function(r){return'<tr>'+cols.map(function(c){var diff=(ctx.summary&&ctx.summary.differing_fields&&ctx.summary.differing_fields[c])?' data-diff="不同条件"':'';return'<td'+diff+'><span class="cell-label">'+(diff?'不同：':'')+'</span>'+esc(r[c]||'未报告')+'</td>'}).join('')+'</tr>'}).join('')+'</tbody></table></div>'}
function renderDossierPaths(items){return'<div class="list">'+((items||[]).map(function(x){return'<div class="card">'+chainPathVisual(x)+'<div class="toolbar">'+(x.dossier_ids||[]).map(function(id){return'<a class="button-sm" href="/dossier/'+encodeURIComponent(id)+'">打开边档案</a>'}).join('')+'</div></div>'}).join('')||'<div class="empty">没有已有机制路径。</div>')+'</div>'}
async function caseList(){var d=await api('/api/cases');title(isPharmaMode()?'研究问题':'Case Explorer',isPharmaMode()?'请选择一个研究问题，进入机制证据阅读。':'Enter through case-focused evidence rather than global frequency.');W.innerHTML+='<div class="grid">'+d.items.map(function(x){return'<a class="card clickable '+(isPharmaMode()?'pharma-card':'')+'" href="/case/'+encodeURIComponent(x.case_id)+'"><h3>'+esc(isPharmaMode()?x.case_id.replaceAll("_"," "):x.case_id)+'</h3><p>'+(isPharmaMode()?'系统已发现：':'')+x.display_triples_count+' 机制关系 · '+x.display_chains_count+(isPharmaMode()?' 条机制链':' chains')+'</p><span class="badge">'+x.fulltext_evidence_count+(isPharmaMode()?' 条全文证据':' fulltext')+'</span><span class="badge conflict">'+(x.non_comparable_records+x.weak_candidates)+(isPharmaMode()?' 条冲突线索':' triage')+'</span>'+renderDeveloperDetails(x)+'</a>'}).join('')+'</div>'}
async function caseDetail(id){var x=await api('/api/case/'+encodeURIComponent(id));title(isPharmaMode()?'研究问题： '+id.replaceAll("_"," "):id,isPharmaMode()?'阅读系统提出的机制线索，并查看证据原文是否支持。':'Case-focused ranking; display scores are navigation heuristics.');W.innerHTML+='<div class="grid"><div class="card metric"><strong>'+x.display_triples_count+'</strong>'+(isPharmaMode()?'机制关系':'triples')+'</div><div class="card metric"><strong>'+x.display_chains_count+'</strong>'+(isPharmaMode()?'机制链':'chains')+'</div><div class="card metric"><strong>'+x.fulltext_evidence_count+'</strong>'+(isPharmaMode()?'全文证据':'fulltext evidence')+'</div><div class="card metric"><strong>'+((x.non_comparable_records||0)+(x.weak_candidates||0))+'</strong>'+(isPharmaMode()?'冲突线索':'triage records')+'</div></div><h2>'+(isPharmaMode()?'系统提出的机制线索':'Top evidence-supported triples')+'</h2><div class="list">'+x.triples.slice(0,30).map(tripleCard).join('')+'</div><h2 class="developer-only">'+(isPharmaMode()?'候选链':'Top candidate chains')+'</h2><div class="list developer-only">'+(x.chains.slice(0,20).map(chainCard).join('')||'<div class="empty">No chains</div>')+'</div>'+renderDeveloperDetails(x,"Case raw / debug")}
async function entities(){title(isPharmaMode()?'研究对象':'Entity Explorer',isPharmaMode()?'查看系统识别到的药物、靶点、通路、疾病和表型。':'Search and filter display KG v2 entities.');W.innerHTML+='<div class="toolbar"><input id="q" placeholder="'+(isPharmaMode()?'搜索研究对象':'Entity label')+'" value="'+esc(new URLSearchParams(location.search).get('q')||'')+'"><select id="etype"><option value="">'+(isPharmaMode()?'全部类型':'All types')+'</option>'+['gene','protein','compound','drug','pathway','biological_process','disease','phenotype','unknown_biomedical_entity'].map(function(x){return'<option>'+x+'</option>'}).join('')+'</select><button class="button" onclick="loadEntities()">'+(isPharmaMode()?'筛选':'Filter')+'</button></div><div id="results"></div>';loadEntities()}
async function loadEntities(){var q=document.querySelector('#q')?document.querySelector('#q').value:'',t=document.querySelector('#etype')?document.querySelector('#etype').value:'',d=await api('/api/entities?limit=100&q='+encodeURIComponent(q)+'&entity_type='+encodeURIComponent(t));document.querySelector('#results').innerHTML='<div class="grid">'+d.items.map(function(x){return'<a class="card clickable" href="/entity/'+x.entity_id+'"><h3>'+esc(x.display_label)+'</h3><span class="badge type">'+esc(isPharmaMode()?humanizeEntityType(x.entity_type):x.entity_type)+'</span><p class="meta">'+(isPharmaMode()?('关联关系 '+x.degree+' · 证据 '+x.evidence_count):('degree '+x.degree+' \xb7 evidence '+x.evidence_count))+'</p>'+renderDeveloperDetails(x)+'</a>'}).join('')+'</div>'}
async function entityDetail(id){var x=await api('/api/entity/'+encodeURIComponent(id));title(x.display_label,isPharmaMode()?humanizeEntityType(x.entity_type):x.entity_type);W.innerHTML+='<div class="card"><p><b>'+(isPharmaMode()?'别名':'Aliases')+':</b> '+(x.aliases||[]).map(esc).join(', ')+'</p><p>'+(isPharmaMode()?('关联关系 '+x.degree+' · 证据 '+x.evidence_count):('Degree '+x.degree+' \xb7 Evidence '+x.evidence_count))+'</p>'+badges(x.ui_badges)+renderDeveloperDetails(x)+'</div><h2>'+(isPharmaMode()?'它可能影响什么':'Outgoing triples')+'</h2><div class="list">'+(x.outgoing_triples.map(tripleCard).join('')||'<div class="empty">None</div>')+'</div><h2>'+(isPharmaMode()?'什么可能影响它':'Incoming triples')+'</h2><div class="list">'+(x.incoming_triples.map(tripleCard).join('')||'<div class="empty">None</div>')+'</div><h2 class="developer-only">Candidate chains</h2><div class="list developer-only">'+x.chains.slice(0,30).map(chainCard).join('')+'</div>'}
async function triples(){title(isPharmaMode()?'机制关系':'Evidence-supported Triples',isPharmaMode()?'系统提出的药物、靶点、通路、疾病或表型之间的机制线索。':'Display KG v2 only; evidence and papers remain side-panel data.');var d=await api('/api/triples?limit=100');W.innerHTML+='<div class="list">'+d.items.map(tripleCard).join('')+'</div>'}
async function chains(){title(isPharmaMode()?'机制链':'Chain View',isPharmaMode()?'把多条机制关系串起来阅读，帮助理解可能的作用路径。':'Linear candidate mechanism paths. Click a chain to see its full detail with triples, evidence, contexts, and review status.');W.innerHTML+='<div class="toolbar"><input id="chain-start" placeholder="'+(isPharmaMode()?'起点研究对象':'Start entity')+'"><input id="chain-end" placeholder="'+(isPharmaMode()?'终点研究对象':'End entity')+'"><label><input id="chain-ft" type="checkbox"> '+(isPharmaMode()?'全文证据':'Fulltext')+'</label><label><input id="chain-results" type="checkbox"> Results</label><label><input id="chain-conflict" type="checkbox"> '+(isPharmaMode()?'冲突线索':'Conflict lens')+'</label><button class="button" onclick="loadChains()">'+(isPharmaMode()?'筛选':'Filter')+'</button></div>'+'<div id="chain-results-list"></div>';loadChains()}
async function loadChains(){var p=new URLSearchParams({limit:100,start_entity:document.querySelector('#chain-start').value,end_entity:document.querySelector('#chain-end').value,has_fulltext:document.querySelector('#chain-ft').checked,has_results:document.querySelector('#chain-results').checked,has_conflict:document.querySelector('#chain-conflict').checked}),d=await api('/api/chains?'+p);var items=asItems(d);document.querySelector('#chain-results-list').innerHTML=(items.length>0?items.map(function(x){return'<article class="card clickable chain-list-card" data-chain-id="'+esc(x.chain_id)+'" onclick="navigateTo(\'/chain/\'+encodeURIComponent(x.chain_id))" title="'+(isPharmaMode()?'查看机制链':'View chain detail')+'">'+chainPathVisual(x)+'<div class="chain-list-meta">'+'<span class="meta">'+(isPharmaMode()?('包含 '+(x.depth||(x.triple_ids||[]).length)+' 条机制关系 · '+(x.fulltext_evidence_count_sum||x.case_fulltext_evidence_count_sum||0)+' 条全文证据'):('Depth '+(x.depth||(x.triple_ids||[]).length)+' · '+(x.fulltext_evidence_count_sum||x.case_fulltext_evidence_count_sum||0)+' fulltext'))+'</span>'+((x.case_ids||[]).length>0?'<span class="badge type developer-only">'+esc((x.case_ids||[]).join(', '))+'</span>':'')+((x.conflict_statuses||[]).length>0?'<span class="badge conflict">'+(isPharmaMode()?'有冲突线索':'has diagnostic')+'</span>':'')+'<button class="button-sm" onclick="event.stopPropagation();navigateTo(\'/chain/\'+encodeURIComponent(x.chain_id))">'+(isPharmaMode()?'查看':'View Chain')+'</button>'+'</div>'+renderDeveloperDetails(x)+'</article>'}).join(''):'<div class="empty">'+(isPharmaMode()?'没有符合条件的机制链。':'No chains match these filters.')+'</div>')}
async function chainPage(id){var d;try{d=await api('/api/chain/'+encodeURIComponent(id))}catch(e){W.innerHTML='<div class="error"><h2>Chain not found</h2><p>'+esc(e.message)+'</p><a class="button" href="/chains">Back to Chains</a></div>';return}var chain=d.chain||{},triples=d.triples||[],evidenceByTriple=d.evidence_by_triple||{},contextsByTriple=d.contexts_by_triple||{},validators=d.validator_annotations||[],conflicts=d.conflict_lens_records||[],review=d.manual_review_summary||{};_renderChainDetail(chain,triples,evidenceByTriple,contextsByTriple,validators,conflicts,review,d.scientific_boundary)}

function _renderChainDetail(chain,triples,evidenceByTriple,contextsByTriple,validators,conflicts,review,boundary){triples=ensureArray(triples);evidenceByTriple=ensureDict(evidenceByTriple);contextsByTriple=ensureDict(contextsByTriple);validators=ensureArray(validators);conflicts=ensureArray(conflicts);if(!review)review={};var html='',totalEvidence=0;for(var tid in evidenceByTriple)totalEvidence+=evidenceByTriple[tid].length;html+='<div class="chain-detail-page">';html+='<a class="button-sm" href="/chains">← '+(isPharmaMode()?'返回机制链':'Back to Chains')+'</a>';html+='<div class="chain-detail-header"><h1>'+(isPharmaMode()?'机制链详情':'Chain Detail')+'</h1><p class="muted">'+(isPharmaMode()?'这是一组可连续阅读的机制线索，需要结合证据原文人工判断。':'This chain is an evidence navigation view. It is not biological validation.')+'</p></div>';html+='<div class="chain-path-hero">'+chainPathVisual(chain)+'</div>';html+='<div class="chain-detail-metrics"><div class="card metric"><strong>'+triples.length+'</strong>'+(isPharmaMode()?'机制关系':'triples in chain')+'</div><div class="card metric"><strong>'+totalEvidence+'</strong>'+(isPharmaMode()?'证据':'evidence records')+'</div><div class="card metric"><strong>'+(chain.fulltext_evidence_count_sum||chain.case_fulltext_evidence_count_sum||0)+'</strong>'+(isPharmaMode()?'全文证据':'fulltext evidence')+'</div>';if((chain.case_ids||[]).length>0)html+='<div class="card metric developer-only"><strong>'+chain.case_ids.length+'</strong>cases</div>';if(review&&review.total>0)html+='<div class="card metric reviewer-only"><strong>'+review.reviewed+'/'+review.total+'</strong>reviewed</div>';html+='</div>';html+='<div class="chain-triple-section"><h2>'+(isPharmaMode()?'链中的机制关系':'Triples in this Chain')+'</h2>';triples.forEach(function(t){html+='<div class="card chain-triple-card" onclick="openTriple(\''+esc(t.triple_id)+'\')"><div class="triple"><span class="entity">'+esc(t.subject_display_label||t.subject_label)+'</span><span class="edge">'+esc(isPharmaMode()?humanizeRelation(t.relation_normalized,t.direction):t.relation_normalized)+'</span><span class="entity">'+esc(t.object_display_label||t.object_label)+'</span></div><p class="meta">'+(t.evidence_count||t.case_evidence_count||0)+(isPharmaMode()?' 条证据 · ':' evidence · ')+(t.fulltext_evidence_count||t.case_fulltext_evidence_count||0)+(isPharmaMode()?' 条全文证据':' fulltext')+'</p>'+renderDeveloperDetails(t)+'</div>'});html+='</div>';html+='<div class="chain-evidence-section"><h2>'+(isPharmaMode()?'证据原文':'Evidence by Triple')+'</h2>';triples.forEach(function(t,idx){var ev=evidenceByTriple[t.triple_id]||[],collapsed=idx>0?' collapsed':'';html+='<div class="chain-evidence-group'+collapsed+'"><h3 class="chain-evidence-toggle" onclick="this.parentElement.classList.toggle(\'collapsed\')">'+esc(t.subject_display_label||t.subject_label)+' '+esc(isPharmaMode()?humanizeRelation(t.relation_normalized,t.direction):t.relation_normalized)+' '+esc(t.object_display_label||t.object_label)+' ['+esc(ev.length)+' evidence]</h3><div class="chain-evidence-body">';if(ev.length===0)html+='<div class="empty">No evidence records for this triple.</div>';ev.forEach(function(e){html+='<div class="evidence evidence-reading-card"><span class="badge reviewer-only">'+esc(e.source_scope||'source')+'</span><span class="badge">'+esc(e.section_title||'unknown section')+'</span><blockquote>'+esc(e.evidence_sentence||e.claim_text||'No text preview')+'</blockquote><p class="meta">PMID '+esc(e.pmid||'—')+'<span class="developer-only"> · '+esc(e.case_id||'')+' · '+esc(e.source_file||'')+':'+esc(e.source_line||'')+'</span></p>'+renderDeveloperDetails(e)+'</div>'});html+='</div></div>'});html+='</div>';var totalContexts=0;for(var ctxtid in contextsByTriple)totalContexts+=contextsByTriple[ctxtid].length;if(totalContexts>0){html+='<div class="chain-context-section"><h2>'+(isPharmaMode()?'上下文':'Contexts')+' ('+totalContexts+')</h2>';triples.forEach(function(t){var ctx=contextsByTriple[t.triple_id]||[];if(ctx.length===0)return;html+='<h4>'+esc(t.subject_display_label||t.subject_label)+' '+esc(t.relation_normalized)+' '+esc(t.object_display_label||t.object_label)+'</h4>';ctx.forEach(function(c){html+='<div class="evidence"><span class="badge type">'+esc(c.context_type||'context')+'</span><blockquote>'+esc(c.context_text||c.description||'No context')+'</blockquote>'+renderDeveloperDetails(c)+'</div>'})});html+='</div>'}if(validators.length>0){html+='<div class="chain-validator-section developer-only"><h2>Validator Annotations ('+validators.length+')</h2>';validators.forEach(function(v){html+='<div class="card"><b>'+esc(v.validator_name||v.validator)+'</b> · '+esc(v.status||'')+'<p class="muted">'+esc(v.summary||'')+'</p>'+renderDeveloperDetails(v)+'</div>'});html+='</div>'}if(conflicts.length>0){html+='<div class="chain-conflict-section"><h2>'+(isPharmaMode()?'冲突线索':'Conflict Lens')+' ('+conflicts.length+')</h2>';conflicts.forEach(function(c){html+='<div class="card"><span class="badge conflict">'+esc(c.record_type)+'</span><span class="badge type developer-only">'+esc(c.case_id||'')+'</span>'+(c.rejection_reason?'<p class="meta">'+esc(c.rejection_reason)+'</p>':'')+renderDeveloperDetails(c)+'</div>'});html+='</div>'}if(review&&review.total>0){html+='<div class="chain-review-section reviewer-only"><h2>Manual Review Status</h2><p class="meta">'+review.reviewed+' of '+review.total+' items reviewed. Manual review labels assess extraction and triage quality, not biological validation.</p></div>'}html+='<div class="chain-scientific-boundary"><p>'+esc(boundary||'This chain is an evidence navigation view. It is not biological validation.')+'</p></div>'+renderDeveloperDetails(chain,"Chain raw / debug")+'</div>';W.innerHTML='<div class="hero" style="padding:20px 28px;margin-bottom:16px"><h1>'+(isPharmaMode()?'机制链详情':'Chain Detail')+'</h1><p>'+(isPharmaMode()?'沿着多个关系阅读可能的机制路径，并检查每条证据是否支持。':'Evidence-supported chain. Click triples to inspect evidence. This is not biological validation.')+'</p></div>'+html}

function chainPathVisual(x){var nodes=x.entity_path||[],rels=x.relation_path||[],html='';for(var i=0;i<nodes.length;i++){html+='<span class="chain-path-node" title="'+esc(nodes[i])+'">'+esc(nodes[i])+'</span>';if(i<rels.length){html+='<span class="chain-path-arrow">→</span>';html+='<span class="chain-path-relation">'+esc(rels[i])+'</span>';html+='<span class="chain-path-arrow">→</span>'}}return'<div class="chain-path">'+html+'</div>'}
function openChain(id){location.href='/chain/'+encodeURIComponent(id)}
function navigateTo(url){location.href=url}
async function conflicts(){title(isPharmaMode()?'冲突线索':'Conflict Lens',isPharmaMode()?'查看系统发现的可能不一致或需要进一步人工判断的证据线索。':'Evidence triage, diagnostic signals, and potential reviewable conflict candidates. Not validated contradictions.');W.innerHTML+='<div class="conflict-summary-cards" id="conflict-summary-cards"><div class="loading">Loading summary…</div></div>'+'<div class="conflict-tabs" id="conflict-tabs"><button class="conflict-tab active" data-bucket="potential_conflict" onclick="switchConflictTab(\'potential_conflict\')">'+(isPharmaMode()?'可能冲突':'Potential Conflicts')+'</button><button class="conflict-tab" data-bucket="mechanism_diagnostic" onclick="switchConflictTab(\'mechanism_diagnostic\')">'+(isPharmaMode()?'机制差异':'Mechanism Diagnostics')+'</button><button class="conflict-tab" data-bucket="rejected_non_comparable" onclick="switchConflictTab(\'rejected_non_comparable\')">'+(isPharmaMode()?'不可比较':'Rejected / Non-comparable')+'</button><button class="conflict-tab" data-bucket="data_quality" onclick="switchConflictTab(\'data_quality\')">'+(isPharmaMode()?'数据质量':'Data Quality')+'</button></div>'+'<div class="conflict-toolbar" id="conflict-toolbar"><select id="conflict-case-filter"><option value="">'+(isPharmaMode()?'全部研究问题':'All cases')+'</option></select><button class="button" onclick="loadConflicts()">'+(isPharmaMode()?'刷新':'Refresh')+'</button></div>'+'<div id="conflict-results"></div>';var sel=document.querySelector('#conflict-case-filter');sel.innerHTML='<option value="">'+(isPharmaMode()?'全部研究问题':'All cases')+'</option>'+cases.map(function(c){return'<option value="'+esc(c.case_id)+'">'+esc(c.case_id)+'</option>'}).join('');sel.onchange=function(){loadConflicts()};_crConflictBucket='potential_conflict';loadConflicts()}
function renderObservationCard(obs,label,warning){if(!obs)obs={};var hasContent=obs.subject||obs.relation||obs.object||obs.preview||obs.evidence_sentence||obs.claim_text;if(warning&&!hasContent)return'<div class="observation-side-card observation-missing"><h5>'+esc(label)+'</h5><p class="badge warn">'+esc(warning)+'</p></div>';return'<div class="observation-side-card"><h5>'+esc(label)+'</h5>'+(obs.subject||obs.relation||obs.object?'<p><b>S-R-O:</b> '+esc(obs.subject||'')+' '+esc(obs.relation||'')+' '+esc(obs.object||'')+(obs.direction?' ['+esc(obs.direction)+']':'')+'</p>':'')+(obs.pmid||obs.pmcid?'<p class="meta">PMID/PMCID: '+esc(obs.pmid||obs.pmcid||'')+'</p>':'')+(obs.preview||obs.evidence_sentence||obs.claim_text?'<blockquote>'+esc(obs.preview||obs.evidence_sentence||obs.claim_text)+'</blockquote>':'')+(obs.paper_title?'<p class="meta">'+esc(obs.paper_title)+'</p>':'')+'</div>'}
function _renderCompactWarning(x){return'<div class="compact-warning-row"><span class="badge warn">'+(isPharmaMode()?'缺少预览':'Missing preview')+'</span><span class="developer-only">Record '+esc(x.review_item_id||x.record_id||'?')+'</span><span class="meta">'+esc(x.record_type)+' · '+esc(x.case_id||'')+'<span class="developer-only"> · '+esc(x.source_file||'')+'</span></span></div>'}
async function loadConflicts(){var bucket=_crConflictBucket||'potential_conflict',caseFilter=document.querySelector('#conflict-case-filter')?document.querySelector('#conflict-case-filter').value:'',params=new URLSearchParams({limit:'200',case_id:caseFilter,bucket:bucket,include_hidden:bucket==='data_quality'?'true':'false'});var d;try{d=await api('/api/conflicts?'+params)}catch(e){document.querySelector('#conflict-results').innerHTML='<div class="error">Failed to load conflict data: '+esc(e.message)+'</div>';return}var summary=asSummary(d),items=asItems(d);_renderConflictSummary(summary,bucket);if(bucket==='potential_conflict'&&items.length===0){_renderEmptyPotentialConflicts(summary);return}if(bucket==='mechanism_diagnostic'){document.querySelector('#conflict-results').innerHTML='<p class="conflict-bucket-notice">Mechanism splits are useful diagnostic signals, not validated conflicts. They indicate where the engine found divergent mechanism interpretations across evidence sources.</p>'+_renderConflictItems(items,bucket);return}if(bucket==='rejected_non_comparable'){document.querySelector('#conflict-results').innerHTML='<p class="conflict-bucket-notice">These records were rejected by the comparability gate and are not weak conflict candidates. They represent direction pairs that the system determined are non-comparable.</p>'+_renderConflictItems(items,bucket);return}if(bucket==='data_quality'){document.querySelector('#conflict-results').innerHTML='<p class="conflict-bucket-notice">Records in this section lack complete observation previews. They may have schema differences or missing extraction fields.</p>'+_renderDataQualityItems(items);return}document.querySelector('#conflict-results').innerHTML=_renderConflictItems(items,bucket)}

var _crConflictBucket='potential_conflict';
function switchConflictTab(bucket){_crConflictBucket=bucket;document.querySelectorAll('.conflict-tab').forEach(function(el){el.classList.toggle('active',el.dataset.bucket===bucket)});loadConflicts()}

function _renderConflictSummary(summary,activeBucket){var cards=document.querySelector('#conflict-summary-cards');if(!cards)return;cards.innerHTML='<div class="card conflict-summary-card'+(activeBucket==='potential_conflict'?' active':'')+'" onclick="switchConflictTab(\'potential_conflict\')"><strong>'+(summary.potential_conflict_count||0)+'</strong>'+(isPharmaMode()?'可能冲突':'Potential Conflicts')+'</div>'+'<div class="card conflict-summary-card'+(activeBucket==='mechanism_diagnostic'?' active':'')+'" onclick="switchConflictTab(\'mechanism_diagnostic\')"><strong>'+(summary.mechanism_diagnostic_count||0)+'</strong>'+(isPharmaMode()?'机制差异':'Mechanism Diagnostics')+'</div>'+'<div class="card conflict-summary-card'+(activeBucket==='rejected_non_comparable'?' active':'')+'" onclick="switchConflictTab(\'rejected_non_comparable\')"><strong>'+(summary.rejected_non_comparable_count||0)+'</strong>'+(isPharmaMode()?'不可比较':'Rejected / Non-comparable')+'</div>'+'<div class="card conflict-summary-card'+(activeBucket==='data_quality'?' active':'')+'" onclick="switchConflictTab(\'data_quality\')"><strong>'+(summary.data_quality_count||0)+'</strong>'+(isPharmaMode()?'数据质量':'Data Quality')+'</div>'}

function _renderEmptyPotentialConflicts(summary){var html='<div class="conflict-empty-state">';html+='<h3>No potential conflict candidates found.</h3>';html+='<p>The current bundles produced mechanism diagnostics or rejected non-comparable pairs, but no reviewable weak/context conflict candidates. This does not mean the case failed — it means the comparability gate did not find reviewable conflict candidates under the current evidence.</p>';html+='<div class="conflict-empty-actions">';if((summary.mechanism_diagnostic_count||0)>0)html+='<button class="button" onclick="switchConflictTab(\'mechanism_diagnostic\')">View Mechanism Diagnostics ('+(summary.mechanism_diagnostic_count||0)+')</button>';if((summary.rejected_non_comparable_count||0)>0)html+='<button class="button" onclick="switchConflictTab(\'rejected_non_comparable\')">View Rejected Pairs ('+(summary.rejected_non_comparable_count||0)+')</button>';if((summary.data_quality_count||0)>0)html+='<button class="button" onclick="switchConflictTab(\'data_quality\')">View Data Quality Warnings ('+(summary.data_quality_count||0)+')</button>';html+='</div></div>';document.querySelector('#conflict-results').innerHTML=html}

function _renderConflictItems(items,bucket){if(!items||items.length===0)return'<div class="empty">No records in this bucket.</div>';return items.map(function(x){var oa=x.observation_a_extracted||{},ob=x.observation_b_extracted||{},aw=x.observation_a_warning,bw=x.observation_b_warning,isSplit=(x.record_type||'').indexOf('split')>=0,hasPair=(oa.subject||oa.preview||ob.subject||ob.preview);if(!hasPair)return _renderCompactWarning(x);return'<div class="card conflict-pair-card">' + '<div class="conflict-pair-header"><span class="badge conflict">'+esc(x.record_type)+'</span><span class="badge type">'+esc(x.case_id||'')+'</span>'+esc(x.candidate_type||x.comparability_label||'')+(isSplit?'<span class="badge warn">Mechanism split: useful diagnostic, not validated conflict.</span>':'')+'</div>'+(x.rejection_reason?'<p class="meta">'+esc(x.rejection_reason)+'</p>':'')+'<div class="conflict-pair-grid">'+renderObservationCard(oa,'Observation A',aw)+renderObservationCard(ob,'Observation B',bw)+'</div>'+((x.linked_triple_ids||[]).length>0?'<div class="toolbar">'+x.linked_triple_ids.map(function(t){return'<button class="button-sm" onclick="openTriple(\''+t+'\')">Linked triple: '+esc(t)+'</button>'}).join(' ')+'</div>':'')+'</div>'}).join('')}

function _renderDataQualityItems(items){if(!items||items.length===0)return'<div class="empty">No data quality issues detected.</div>';var missingPreview=items.filter(function(x){var oa=x.observation_a_extracted||{},ob=x.observation_b_extracted||{};return !(oa.subject||oa.preview||ob.subject||ob.preview)});var withPreview=items.filter(function(x){var oa=x.observation_a_extracted||{},ob=x.observation_b_extracted||{};return oa.subject||oa.preview||ob.subject||ob.preview});var html='';if(missingPreview.length>0){html+='<h4>'+missingPreview.length+' records missing observation previews</h4>';html+=missingPreview.map(function(x){return _renderCompactWarning(x)}).join('')}if(withPreview.length>0){html+='<h4>'+withPreview.length+' data-quality records with partial previews</h4>';html+=withPreview.map(function(x){var oa=x.observation_a_extracted||{},ob=x.observation_b_extracted||{};return'<div class="card conflict-pair-card"><div class="conflict-pair-header"><span class="badge warn">'+esc(x.record_type)+'</span><span class="badge type">'+esc(x.case_id||'')+'</span></div>'+'<div class="conflict-pair-grid">'+renderObservationCard(oa,'Observation A',x.observation_a_warning)+renderObservationCard(ob,'Observation B',x.observation_b_warning)+'</div>'+'</div>'}).join('')}return html||'<div class="empty">No data quality issues.</div>'}
