var VALIDATOR_TERMS={};['lincs','reactome','enrichr','pubmed','pubmed validator','lincs validator','reactome validator','enrichr validator'].forEach(function(t){VALIDATOR_TERMS[t]=true});
function isBiomedical(label,etype){if(!label)return false;var lo=label.toLowerCase();if(VALIDATOR_TERMS[lo])return false;if(etype&&(etype.indexOf('validator')>=0||etype.indexOf('database')>=0))return false;return true}
var _focusedEntity=null,_allGraphTriples=[],_activeTripleId=null;
function entityNode(label,etype,side){return'<span class="triple-node '+side+'" data-entity="'+esc(label)+'" title="'+esc(label)+(etype?' ('+esc(etype)+')':'')+'" onclick="event.stopPropagation();focusEntity(\''+esc(label)+'\')">'+esc(label)+'</span>'}
function renderTripleRows(triples,highlightEntity){var html='';triples.forEach(function(t){var subj=t.subject_display_label||t.subject_label,obj=t.object_display_label||t.object_label,rel=t.relation_normalized,eb=[],rowClass='triple-row';if(t.fulltext_evidence_count>0)eb.push('<span class="badge">fulltext</span>');if((t.results_section_evidence_count||0)>0)eb.push('<span class="badge">Results</span>');if((t.case_ids||[]).length>1)eb.push('<span class="badge type">multi-case</span>');if(t.conflict_status&&t.conflict_status!=='none')eb.push('<span class="badge conflict">conflict lens</span>');if(highlightEntity&&(subj===highlightEntity||obj===highlightEntity))rowClass+=' highlighted-row';html+='<div class="'+rowClass+'" data-triple-id="'+esc(t.triple_id)+'" data-subject="'+esc(subj)+'" data-object="'+esc(obj)+'" onclick="clickTripleRow(\''+esc(t.triple_id)+'\',this)"><div class="triple-row-inner">'+entityNode(subj,t.subject_entity_type,'subject')+'<span class="triple-arrow">\u2192</span><span class="triple-relation">'+esc(rel)+'</span><span class="triple-arrow">\u2192</span>'+entityNode(obj,t.object_entity_type,'object')+'</div><div class="triple-badges">'+eb.join('')+'</div></div>'});return html||'<div class="empty">No triples match these filters.</div>'}
function clickTripleRow(tripleId,rowEl){document.querySelectorAll('.triple-row.selected-row').forEach(function(r){r.classList.remove('selected-row')});if(rowEl)rowEl.classList.add('selected-row');openTriple(tripleId)}
async function showTripleDetailById(tripleId){try{var t=await api('/api/triple/'+encodeURIComponent(tripleId)+'?evidence_limit=30'),detail=document.querySelector('#graph-detail');detail.innerHTML='<div class="card graph-detail-card"><h3>'+esc(t.subject_display_label)+' <span class="triple-relation">'+esc(t.relation_normalized)+'</span> '+esc(t.object_display_label)+'</h3>'+badges(t.ui_badges)+'<p class="meta">'+t.evidence_total+' evidence \xb7 '+t.fulltext_evidence_count+' fulltext \xb7 Cases: '+((t.case_ids||[]).join(', '))+'</p><div class="toolbar"><button class="button-sm" onclick="filterEvidence(\''+tripleId+'\',\'\')">All</button><button class="button-sm" onclick="filterEvidence(\''+tripleId+'\',\'fulltext\')">Fulltext</button><button class="button-sm" onclick="filterEvidence(\''+tripleId+'\',\'results\')">Results</button></div><div id="evidence-list">'+evidenceHtml(t.evidence_links)+'</div><h4>Validator annotations</h4>'+((t.validator_annotations||[]).map(function(v){return'<div class="card"><b>'+esc(v.validator_name)+'</b> \xb7 '+esc(v.status)+'<p class="muted">'+esc(v.summary)+'</p></div>'}).join('')||'<div class="empty">None</div>')+'<h4>Conflict Lens</h4>'+((t.conflict_lens_records||[]).map(function(c){return'<div class="card"><span class="badge conflict">'+esc(c.record_type)+'</span><p>'+esc(c.rejection_reason||'Triage record')+'</p></div>'}).join('')||'<div class="empty">None</div>')+'</div>';detail.scrollIntoView({behavior:'smooth'})}catch(e){document.querySelector('#graph-detail').innerHTML='<div class="error">Failed to load triple detail: '+esc(e.message)+'</div>'}}
function focusEntity(label){_focusedEntity=label;var banner=document.querySelector('#entity-focus-banner');if(!banner){var b=document.createElement('div');b.id='entity-focus-banner';b.className='entity-focus-banner';b.innerHTML='<span>Focused entity: <strong id="focus-label"></strong></span><button class="button-sm" onclick="clearEntityFocus()">Clear focus</button>';document.querySelector('#graph-layout').before(b)}else{banner.style.display='flex'}document.querySelector('#focus-label').textContent=label;renderFilteredTriples()}
function clearEntityFocus(){_focusedEntity=null;var banner=document.querySelector('#entity-focus-banner');if(banner)banner.style.display='none';document.querySelectorAll('.triple-row').forEach(function(r){r.classList.remove('highlighted-row')});renderFilteredTriples()}


function filterEvidence(scope){var el=document.querySelector('#evidence-list');if(!el)return;var btns=document.querySelectorAll('.evidence-filter-btn');btns.forEach(function(b){var t=(b.textContent||'').toLowerCase();b.classList.toggle('active',!scope&&t==='all'||!!scope&&t.indexOf(scope)>=0)});var items=el.querySelectorAll('.evidence');items.forEach(function(e){if(!scope){e.style.display='';return}var badge=e.querySelector('.badge');var txt=badge?badge.textContent.toLowerCase():'';if(scope==='fulltext'){e.style.display=txt.indexOf('fulltext')>=0?'':''}else if(scope==='results'){e.style.display=txt.indexOf('results')>=0?'':''}else{e.style.display=''}})}
function renderFilteredTriples(){var triples=_allGraphTriples,container=document.querySelector('#graph-layout');if(!container)return;if(_focusedEntity){var incoming=[],outgoing=[];triples.forEach(function(t){var s=t.subject_display_label||t.subject_label,o=t.object_display_label||t.object_label;if(s===_focusedEntity)outgoing.push(t);if(o===_focusedEntity)incoming.push(t)});var html='';if(incoming.length>0)html+='<h4 class="triple-section-label">\u25bc Incoming ('+incoming.length+')</h4>'+renderTripleRows(incoming,_focusedEntity);if(outgoing.length>0)html+='<h4 class="triple-section-label">\u25b2 Outgoing ('+outgoing.length+')</h4>'+renderTripleRows(outgoing,_focusedEntity);if(!html)html='<div class="empty">No triples found for '+esc(_focusedEntity)+'.</div>';container.innerHTML=html}else{container.innerHTML=renderTripleRows(triples)}}
async function graphView(){title(isPharmaMode()?'关系图':'Knowledge Graph',isPharmaMode()?'按主体、关系、客体浏览机制线索，点击一行查看证据。':'Triple-centric graph. Click entity to focus; click row for evidence.');W.innerHTML+='<div class="graph-controls"><select id="graph-case-filter"><option value="">'+(isPharmaMode()?'全部研究问题':'All cases')+'</option></select><input id="graph-search" placeholder="'+(isPharmaMode()?'搜索研究对象':'Search entities\u2026')+'"><select id="graph-limit"><option value="30">Top 30</option><option value="50" selected>Top 50</option><option value="100">Top 100</option></select><button class="button" onclick="loadGraph()">'+(isPharmaMode()?'刷新':'Refresh')+'</button><span id="graph-stats" class="meta"></span></div><div id="entity-focus-banner" class="entity-focus-banner" style="display:none"><span>'+(isPharmaMode()?'当前研究对象':'Focused entity')+': <strong id="focus-label"></strong></span><button class="button-sm" onclick="clearEntityFocus()">'+(isPharmaMode()?'取消':'Clear focus')+'</button></div><div class="graph-layout" id="graph-layout"><div class="loading">Loading triples\u2026</div></div>';var sel=document.querySelector('#graph-case-filter');sel.innerHTML='<option value="">'+(isPharmaMode()?'全部研究问题':'All cases')+'</option>'+cases.map(function(c){return'<option value="'+esc(c.case_id)+'">'+esc(c.case_id)+'</option>'}).join('');sel.onchange=function(){loadGraph()};document.querySelector('#graph-search').onkeydown=function(e){if(e.key==='Enter')loadGraph()};_focusedEntity=null;loadGraph()}
async function loadGraph(){var caseFilter=document.querySelector('#graph-case-filter')?document.querySelector('#graph-case-filter').value:'',searchQ=(document.querySelector('#graph-search')?document.querySelector('#graph-search').value:'').toLowerCase(),limit=parseInt(document.querySelector('#graph-limit')?document.querySelector('#graph-limit').value:'50'),params=new URLSearchParams({limit:String(Math.max(limit,150)),case_id:caseFilter});var triplesData;try{triplesData=await api('/api/triples?'+params)}catch(e){document.querySelector('#graph-layout').innerHTML='<div class="empty">Unable to load knowledge graph. Please run system_b_build_clean_kg first.</div>';document.querySelector('#graph-stats').textContent='Load failed';return}var triples=asItems(triplesData);if(triples.length===0){document.querySelector('#graph-layout').innerHTML='<div class="empty">No display KG found. Please run system_b_build_clean_kg first.</div>';return}triples=triples.filter(function(t){return isBiomedical(t.subject_display_label)&&isBiomedical(t.object_display_label)});if(searchQ){triples=triples.filter(function(t){return(t.subject_display_label||'').toLowerCase().indexOf(searchQ)>=0||(t.object_display_label||'').toLowerCase().indexOf(searchQ)>=0||(t.relation_normalized||'').toLowerCase().indexOf(searchQ)>=0})}triples=triples.slice(0,limit);_allGraphTriples=triples;_focusedEntity=null;var banner=document.querySelector('#entity-focus-banner');if(banner)banner.style.display='none';document.querySelector('#graph-stats').textContent=triples.length+' triples displayed';renderFilteredTriples()}
function highlightGraphNode(label,side){document.querySelectorAll('.triple-row').forEach(function(r){var s=r.dataset.subject,o=r.dataset.object;if(s===label||o===label)r.classList.add('highlighted-row');else r.classList.remove('highlighted-row')})}
function highlightGraphTriple(tripleId){document.querySelectorAll('.triple-row').forEach(function(r){r.classList.toggle('highlighted-row',r.dataset.tripleId===tripleId)})}
function showGraphTripleDetail(t){openTriple(t.triple_id||t.tripleId)}
var _globalGraphData=null,_graphSelectedEdge=null,_graphSelectedNode=null;
async function graphView(){title('全局证据地图 Global Evidence Map','跨研究问题探索实体、机制邻域、路径、证据强度、上下文分歧和人工审核状态。');W.innerHTML+='<div class="global-graph-workspace"><div class="graph-topbar"><input id="graph-search" placeholder="搜索实体/药物/基因/通路"><select id="graph-view-mode"><option value="global">结构地图</option><option value="path">路径视图</option><option value="evidence">证据强度</option><option value="conflict">上下文分歧</option><option value="review">人工审核状态</option><option value="list">列表视图</option></select><select id="graph-case-filter"></select><button class="button-sm" onclick="loadGraph()">重置</button><button class="button-sm" onclick="fitGraphCanvas()">适应画布</button><button class="button-sm" onclick="saveLibraryItem(\'graph\',{id:\'graph-\'+Date.now(),label:\'保存的证据地图视图\',href:\'/graph\'})">保存视图</button></div><aside class="graph-filter-panel"><h3>过滤器</h3><label>实体类型<select id="graph-entity-type"></select></label><label><input id="graph-fulltext" type="checkbox"> 仅全文支持</label><label><input id="graph-conflict" type="checkbox"> 仅分歧线索</label><label>节点上限<select id="graph-node-limit"><option>80</option><option selected>150</option><option>250</option></select></label><div class="path-controls"><h4>机制路径</h4><input id="path-source" placeholder="起点"><input id="path-target" placeholder="终点"><button class="button-sm" onclick="loadGraphPath()">查看路径</button></div><div class="path-controls"><h4>Compare Mode</h4><input id="compare-a" placeholder="实体 A"><input id="compare-b" placeholder="实体 B"><button class="button-sm" onclick="renderGraphCompare()">比较已有连接</button></div><div class="path-controls developer-only"><h4>Story Mode</h4><input id="story-title" placeholder="标题"><button class="button-sm" onclick="saveGraphStory()">保存本地 Story</button><p class="meta">故事保存在当前浏览器</p></div></aside><section class="graph-canvas-panel"><svg id="global-graph-svg" role="img" aria-label="Global Evidence Map"></svg><div class="graph-minimap" aria-label="Minimap">Minimap</div><div class="graph-legend">图例：形状表示实体类型；线型表示全文/摘要支持；文字 badge 同时表达证据、分歧和审核状态。</div><div id="graph-list-alt" class="graph-list-alt"></div></section><aside class="graph-detail-side" id="graph-detail-side"><div class="empty">点击节点或边查看详情。</div></aside><footer class="graph-status" id="graph-status"></footer></div>';var f=await api('/api/graph/filters');document.querySelector('#graph-case-filter').innerHTML='<option value="">全部研究问题</option>'+f.cases.map(function(c){return'<option value="'+esc(c)+'">'+esc(c)+'</option>'}).join('');document.querySelector('#graph-entity-type').innerHTML='<option value="">全部实体类型</option>'+f.entity_types.map(function(t){return'<option value="'+esc(t)+'">'+esc(humanizeEntityType(t))+'</option>'}).join('');['graph-case-filter','graph-entity-type','graph-fulltext','graph-conflict','graph-node-limit','graph-view-mode'].forEach(function(id){document.querySelector('#'+id).onchange=loadGraph});document.querySelector('#graph-search').oninput=function(){renderGlobalGraph()};loadGraph()}
async function loadGraph(){var p=new URLSearchParams({limit_nodes:document.querySelector('#graph-node-limit').value,limit_edges:'260',case_id:document.querySelector('#graph-case-filter').value,entity_type:document.querySelector('#graph-entity-type').value});if(document.querySelector('#graph-fulltext').checked)p.set('has_fulltext','1');if(document.querySelector('#graph-conflict').checked)p.set('has_conflict','1');_globalGraphData=await api('/api/graph/overview?'+p);_graphSelectedEdge=null;_graphSelectedNode=null;renderGlobalGraph()}
function renderGlobalGraph(){var svg=document.querySelector('#global-graph-svg');if(!svg||!_globalGraphData)return;var q=(document.querySelector('#graph-search')?document.querySelector('#graph-search').value:'').toLowerCase(),nodes=_globalGraphData.nodes,edges=_globalGraphData.edges;if(q){var keep=new Set(nodes.filter(function(n){return(n.label||'').toLowerCase().indexOf(q)>=0}).map(function(n){return n.id}));edges=edges.filter(function(e){return keep.has(e.source)||keep.has(e.target)});keep=new Set([].concat(...edges.map(function(e){return[e.source,e.target]})));nodes=nodes.filter(function(n){return keep.has(n.id)||(n.label||'').toLowerCase().indexOf(q)>=0})}var w=900,h=560,cx=w/2,cy=h/2,r=Math.min(w,h)*.36,pos={};nodes.forEach(function(n,i){var a=(Math.PI*2*i/Math.max(1,nodes.length));pos[n.id]={x:cx+Math.cos(a)*r*(.55+(i%5)/10),y:cy+Math.sin(a)*r*(.55+(i%7)/12)}});var edgeHtml=edges.map(function(e){var a=pos[e.source],b=pos[e.target];if(!a||!b)return'';var full=(e.fulltext_evidence_count||0)>0,width=1+Math.min(6,e.evidence_count||0);return'<g class="graph-edge '+(_graphSelectedEdge===e.id?'selected':'')+'" data-graph-edge-id="'+esc(e.id)+'"><line x1="'+a.x+'" y1="'+a.y+'" x2="'+b.x+'" y2="'+b.y+'" stroke-width="'+width+'" stroke-dasharray="'+(full?'':'6 5')+'"></line><text x="'+((a.x+b.x)/2)+'" y="'+((a.y+b.y)/2)+'">'+esc(e.relation_label||e.relation)+'</text></g>'}).join('');var nodeHtml=nodes.map(function(n){var p=pos[n.id],size=18+Math.min(18,n.evidence_count||0),cls='graph-node type-'+String(n.entity_type||'unknown').replace(/[^a-z0-9_-]/gi,'_')+(_graphSelectedNode===n.id?' selected':'');return'<g class="'+cls+'" data-graph-node-id="'+esc(n.id)+'" transform="translate('+p.x+' '+p.y+')">'+nodeShapeSvg(n,size)+'<text y="'+(size+14)+'">'+esc(n.label||n.id)+'</text></g>'}).join('');svg.setAttribute('viewBox','0 0 '+w+' '+h);svg.innerHTML=edgeHtml+nodeHtml;var list=document.querySelector('#graph-list-alt');if(list)list.innerHTML='<h3>列表替代视图</h3>'+edges.slice(0,80).map(function(e){return'<div class="compact-warning-row"><span>'+esc(e.source_label)+' '+esc(e.relation_label||e.relation)+' '+esc(e.target_label)+'</span><a class="button-sm" href="/dossier/'+encodeURIComponent(e.id)+'">打开档案</a></div>'}).join('');document.querySelector('#graph-status').textContent='当前节点 '+nodes.length+' / 总节点 '+_globalGraphData.summary.total_nodes+' · 当前边 '+edges.length+' / 总边 '+_globalGraphData.summary.total_edges+' · cluster 仅用于 UI 布局，不写回 KG。'}
function nodeShapeSvg(n,size){var t=String(n.entity_type||'').toLowerCase();if(/compound|drug/.test(t))return'<rect x="'+(-size*1.4)+'" y="'+(-size*.7)+'" width="'+(size*2.8)+'" height="'+(size*1.4)+'" rx="8"></rect>';if(/pathway/.test(t))return'<polygon points="'+[-size+',0',-size/2+','+(-size*.85),size/2+','+(-size*.85),size+',0',size/2+','+(size*.85),-size/2+','+(size*.85)].join(' ')+'"></polygon>';if(/biological_process/.test(t))return'<ellipse rx="'+(size*1.4)+'" ry="'+(size*.8)+'"></ellipse>';if(/disease/.test(t))return'<circle r="'+size+'"></circle><circle r="'+(size-4)+'"></circle>';if(/phenotype|outcome/.test(t))return'<polygon points="0,'+(-size)+' '+size+',0 0,'+size+' '+(-size)+',0"></polygon>';if(/cell|tissue/.test(t))return'<rect x="'+(-size)+'" y="'+(-size*.55)+'" width="'+(size*2)+'" height="'+(size*1.1)+'" rx="5"></rect>';return'<circle r="'+size+'"></circle>'}
