function graphPositions(nodes,edges,w,h){var neighbors={},seen=new Set(),components=[];nodes.forEach(function(n){neighbors[n.id]=[]});edges.forEach(function(e){if(neighbors[e.source]&&neighbors[e.target]){neighbors[e.source].push(e.target);neighbors[e.target].push(e.source)}});nodes.slice().sort(function(a,b){return(b.score||0)-(a.score||0)}).forEach(function(n){if(seen.has(n.id))return;var queue=[n.id],component=[];seen.add(n.id);while(queue.length){var id=queue.shift();component.push(id);neighbors[id].forEach(function(next){if(!seen.has(next)){seen.add(next);queue.push(next)}})}components.push(component)});components.sort(function(a,b){return b.length-a.length});var cols=Math.ceil(Math.sqrt(components.length)),rows=Math.ceil(components.length/cols),cellW=w/cols,cellH=h/rows,pos={};components.forEach(function(component,index){var cx=(index%cols+.5)*cellW,cy=(Math.floor(index/cols)+.5)*cellH,r=Math.min(cellW,cellH)*Math.min(.38,.12+.025*component.length);component.forEach(function(id,i){var angle=-Math.PI/2+Math.PI*2*i/Math.max(1,component.length),radius=component.length===1?0:r*(.65+.35*(i%3)/2);pos[id]={x:cx+Math.cos(angle)*radius,y:cy+Math.sin(angle)*radius}})});return pos}
