return'<g class="graph-edge '+(selected?'selected':'')+'" data-graph-edge-id="'+esc(e.id)+'" tabindex="0"><title>'+esc(e.source_label+' '+(e.relation||'affects')+' '+e.target_label)+'</title><line class="edge-hit-target" '+line+'></line><line class="edge-visible" '+line+' stroke-width="'+width+'" stroke-dasharray="'+(full?'':'6 5')+'"></line><text class="edge-label" x="'+((a.x+b.x)/2)+'" y="'+((a.y+b.y)/2)+'">'+esc(e.relation_label||e.relation)+'</text></g>'
