function ownerSecurityPage(){W.innerHTML+='<div class="card"><h2>Security Rules</h2><ul><li>Owner is unique and cannot be created from Access UI.</li><li>Invite codes, reset tokens, and temporary passwords are shown once only.</li><li>Hashes only are stored in the database.</li><li>Disabling a user preserves annotation, audit, adjudication, Gold, and metric provenance.</li><li>Session version invalidates stale sessions after password reset, role change, disable, or revoke.</li></ul></div>'}
async function ownerPilotSetupPage(){var users=await api('/api/owner/users'),projects=await api('/api/owner/projects');var reviewers=asItems(users).filter(function(u){return u.enabled&&u.role==='reviewer'}),adjudicators=asItems(users).filter(function(u){return u.enabled&&['adjudicator','reviewer'].indexOf(u.role)>=0});W.innerHTML='<section class="card"><h2>Pilot Setup Wizard</h2><p class="meta">Namespace is fixed to pilot. Review Item count is not Case count.</p><div class="secondary-field-grid"><label>Pilot name<input id="pilot-name" value="Owner-created Pilot"></label><label>Description<input id="pilot-desc"></label><label>Guideline version<input id="pilot-guideline" value="atlas_annotation_v1"></label><label>Case IDs, comma separated<input id="pilot-cases" placeholder="empty = all pilot items"></label><label>Item types, comma separated<input id="pilot-types" placeholder="empty = all item types"></label><label>Source scope<input id="pilot-source" placeholder="optional"></label><label>Primary reviewer<select id="pilot-primary"><option value=""></option>'+reviewers.map(function(u){return'<option value="'+esc(u.user_id)+'">'+esc(u.username)+' ('+esc(u.role)+')</option>'}).join('')+'</select></label><label>Secondary reviewer<select id="pilot-secondary"><option value=""></option>'+reviewers.map(function(u){return'<option value="'+esc(u.user_id)+'">'+esc(u.username)+' ('+esc(u.role)+')</option>'}).join('')+'</select></label><label>Adjudicator<select id="pilot-adjudicator"><option value=""></option>'+adjudicators.map(function(u){return'<option value="'+esc(u.user_id)+'">'+esc(u.username)+' ('+esc(u.role)+')</option>'}).join('')+'</select></label><label>Batch size<input id="pilot-batch" type="number" min="1" value="20"></label><label>Random seed<input id="pilot-seed" value="pilot-seed-1"></label></div><div class="toolbar"><button class="button" onclick="ownerPilotPreview()">Preview assignments</button><button class="button-sm" onclick="ownerPilotCreate()">Create Pilot from preview</button><button class="button-sm" onclick="ownerCorrectPilotNamespace()">Correct existing empty Pilot namespace</button></div><div id="pilot-preview" aria-live="polite"></div><div id="pilot-fix-result"></div></section><div class="card"><h2>Existing Projects</h2><div class="table-scroll"><table><caption>Owner projects</caption><thead><tr><th scope="col">name</th><th scope="col">namespace</th><th scope="col">status</th><th scope="col">cases</th><th scope="col">items</th><th scope="col">assignments</th><th scope="col">Gold</th></tr></thead><tbody>'+asItems(projects).map(function(p){return'<tr><td>'+esc(p.name)+'</td><td>'+esc(p.namespace)+'</td><td>'+esc(p.status)+'</td><td>'+esc(p.unique_cases)+'</td><td>'+esc(p.unique_review_items)+'</td><td>'+esc(p.assignment_count)+'</td><td>'+esc(p.gold_dataset_version||'not frozen')+'</td></tr>'}).join('')+'</tbody></table></div></div>'}
function ownerPilotPayload(){return{name:document.querySelector('#pilot-name').value,description:document.querySelector('#pilot-desc').value,namespace:'pilot',annotation_schema_version:document.querySelector('#pilot-guideline').value,case_ids:document.querySelector('#pilot-cases').value.split(',').map(function(x){return x.trim()}).filter(Boolean),item_types:document.querySelector('#pilot-types').value.split(',').map(function(x){return x.trim()}).filter(Boolean),source_scope:document.querySelector('#pilot-source').value||null,primary_reviewer_user_id:document.querySelector('#pilot-primary').value,secondary_reviewer_user_id:document.querySelector('#pilot-secondary').value,adjudicator_user_id:document.querySelector('#pilot-adjudicator').value,batch_size:Number(document.querySelector('#pilot-batch').value||20),random_seed:document.querySelector('#pilot-seed').value}}
