async function ownerSystemStatePage(){var d=await api('/api/owner/system-state');W.innerHTML+='<div class="card"><h2>System State</h2><p><span class="badge">DB '+esc(d.database_path)+'</span><span class="badge">Schema '+esc(d.schema_head)+'</span><span class="badge">Owner '+esc((d.owner&&d.owner.username)||'missing')+'</span></p></div><div class="grid"><div class="card metric"><strong>'+esc(d.assignment_batch_count)+'</strong>assignment batches</div><div class="card metric"><strong>'+esc(d.adjudication_count)+'</strong>adjudications</div><div class="card metric"><strong>'+esc(d.metric_result_count)+'</strong>metric results</div><div class="card metric"><strong>'+esc(d.active_invite_count)+'</strong>active invites</div></div><div class="card"><h2>Projects by namespace</h2><pre>'+esc(JSON.stringify(d.projects,null,2))+'</pre></div><div class="card"><h2>Review items</h2><pre>'+esc(JSON.stringify({by_namespace:d.review_items_by_namespace,by_project:d.review_items_by_project},null,2))+'</pre></div><div class="card"><h2>Assignments</h2><pre>'+esc(JSON.stringify(d.assignment_counts,null,2))+'</pre></div><div class="card"><h2>Annotations / Gold / Metrics</h2><pre>'+esc(JSON.stringify({annotations:d.annotation_counts,gold:d.gold_counts,metric_runs:d.metric_run_counts},null,2))+'</pre></div><div class="card"><h2>Quality warnings</h2><pre>'+esc(JSON.stringify(d.quality_warnings,null,2))+'</pre></div>'}
