function renderAdjudicationQueue(rows){return rows.length?'<div class="adjudication-layout"><div class="list adjudication-queue">'+rows.map(function(row){return'<button class="card adjudication-queue-item" onclick="openAdjudicationItem(\''+esc(row.project_id)+'\',\''+esc(row.review_item_id)+'\')"><span class="badge conflict">需要仲裁</span><strong>'+esc(shortId(row.review_item_id))+'</strong><span class="meta">'+esc(Object.keys(row.field_differences||{}).length)+' differing fields</span></button>'}).join('')+'</div><div id="adjudication-detail"><div class="empty">Select a disagreement to compare Reviewer A and B.</div></div></div>':'<div class="empty">No unresolved disagreements for this project.</div>'}
