async function adjudicationWorkspace(){title('我的仲裁','只有分配给你、Primary 与 Secondary 均已提交且确有分歧的任务才会显示答案。');var s=await api('/api/adjudication/summary'),d=await api('/api/adjudication/queue');W.innerHTML+='<section class="readiness-hero '+(s.pending_count?'is-ready':'')+'"><span class="eyebrow">Adjudication assignment</span><h2>'+esc(s.pending_count)+' 个任务等待仲裁</h2><p>'+esc(s.waiting_for_double_review_count)+' 个任务仍在等待双人审核完成。</p></section><div class="metric-grid"><div class="card metric"><strong>'+esc(s.pending_count)+'</strong>待仲裁</div><div class="card metric"><strong>'+esc(s.completed_count)+'</strong>已仲裁</div><div class="card metric"><strong>'+esc(s.guideline_ambiguity_count)+'</strong>指南歧义</div><div class="card metric"><strong>'+esc(s.insufficient_evidence_count)+'</strong>证据不足</div></div><section><h2>分配给我的分歧</h2>'+((d.items||[]).length?renderAdjudicationQueue(d.items):'<div class="empty"><h3>当前没有等待你仲裁的任务</h3><p>未完成双标的答案不会发送到本页面。</p><a class="button-sm" href="/discover">浏览研究资料</a></div>')+'</section>'}
async function openAdjudicationItem(projectId,itemId){var target=document.querySelector('#adjudication-detail');target.innerHTML='<div class="loading">Loading disagreement...</div>';try{var d=await api('/api/adjudication/'+encodeURIComponent(itemId)+'?project_id='+encodeURIComponent(projectId)),item=d.review_item||{},annotations=d.annotations||[],diffs=d.comparison&&d.comparison.field_differences||{};target.innerHTML='<section class="card adjudication-evidence"><span class="badge type">'+esc(item.item_type||'review item')+'</span><h2>'+esc(item.subject||item.paper_title||shortId(itemId))+'</h2><blockquote>'+esc(item.evidence_sentence||item.claim_text||item.rejection_reason||'No evidence preview available.')+'</blockquote><p class="meta">'+esc(item.subject||'-')+' · '+esc(item.relation||'-')+' · '+esc(item.object||'-')+'</p></section><div class="adjudication-compare">'+annotations.map(function(a){return'<article class="card"><h3>'+esc(a.reviewer_label)+'</h3><p><span class="badge">'+esc(a.final_label||'no label')+'</span></p><dl>'+Object.entries(a.structured_fields||{}).map(function(pair){return'<dt>'+esc(pair[0])+'</dt><dd>'+esc(Array.isArray(pair[1])?pair[1].join(', '):pair[1])+'</dd>'}).join('')+'</dl></article>'}).join('')+'</div><section class="card"><h3>Field differences</h3>'+(Object.keys(diffs).length?'<dl>'+Object.entries(diffs).map(function(pair){return'<dt>'+esc(pair[0])+'</dt><dd>A: '+esc(pair[1][0])+' · B: '+esc(pair[1][1])+'</dd>'}).join('')+'</dl>':'<p class="empty">No field-level differences.</p>')+'<div class="secondary-field-grid"><label for="adj-label">Final label<select id="adj-label"><option value="">Select...</option><option>VALID</option><option>PARTIAL</option><option>INVALID</option><option>UNCLEAR</option></select></label><label for="adj-notes">Decision notes<textarea id="adj-notes" rows="3"></textarea></label></div><button class="button" id="adj-submit" data-project="'+esc(projectId)+'" data-item="'+esc(itemId)+'" data-revision="'+esc(d.current_revision||0)+'" onclick="submitAdjudicationDecision(this)">Submit adjudication</button><div id="adj-message" aria-live="polite"></div></section>'}catch(e){showPageError('#adjudication-detail','Unable to load disagreement',e,'openAdjudicationItem(\''+esc(projectId)+'\',\''+esc(itemId)+'\')')}}
async function submitAdjudicationDecision(button){var label=document.querySelector('#adj-label').value,msg=document.querySelector('#adj-message');if(!label){msg.innerHTML='<p class="error">Select a final label.</p>';return}if(!confirm('Submit this adjudication as a new Gold candidate revision?'))return;button.disabled=true;try{await apiPost('/api/adjudication/'+encodeURIComponent(button.dataset.item),{project_id:button.dataset.project,final_label:label,notes:document.querySelector('#adj-notes').value,expected_revision:Number(button.dataset.revision||0)});msg.innerHTML='<span class="badge saved-indicator">Adjudication submitted; Gold remains unfrozen.</span>';showToast('Adjudication submitted','success')}catch(e){msg.innerHTML='<p class="error">'+esc(e.message)+'</p>'}finally{button.disabled=false}}
async function ownerGoldPage(projectId){if(!projectId){W.innerHTML='<div class="empty">Select a project to inspect Gold readiness.</div>';return}var readiness=await api('/api/owner/gold/readiness?project_id='+encodeURIComponent(projectId)),candidates=await api('/api/owner/gold/candidates?project_id='+encodeURIComponent(projectId));W.innerHTML='<div class="grid"><div class="card metric"><strong>'+esc(readiness.ready?'ready':'blocked')+'</strong>Freeze readiness</div><div class="card metric"><strong>'+esc((candidates.items||[]).length)+'</strong>Candidate revisions</div></div><section class="card"><h2>Blocking reasons</h2>'+(readiness.blocked_reasons||[]).map(function(reason){return'<p class="badge warn">'+esc(reason)+'</p>'}).join('')+(readiness.ready?'<p class="badge saved-indicator">All freeze checks passed.</p>':'')+'<div class="toolbar"><button class="button" '+(readiness.ready?'':'disabled')+' onclick="ownerFreezeGold(\''+esc(projectId)+'\')">Freeze next Pilot/Production Gold version</button></div><div id="gold-message" aria-live="polite"></div></section><div class="table-scroll"><table><caption>Gold candidate and frozen revisions</caption><thead><tr><th scope="col">Review item</th><th scope="col">Label</th><th scope="col">Status</th><th scope="col">Candidate revision</th><th scope="col">Dataset version</th></tr></thead><tbody>'+(candidates.items||[]).map(function(row){return'<tr><td>'+esc(shortId(row.review_item_id))+'</td><td>'+esc(row.final_gold_label)+'</td><td>'+esc(row.status)+'</td><td>'+esc(row.candidate_revision)+'</td><td>'+esc(row.gold_dataset_version||'not frozen')+'</td></tr>'}).join('')+'</tbody></table></div>'}
