async function guidelineWorkspace(schemaId){var g=await api('/api/guidelines/'+encodeURIComponent(schemaId));title('Guidelines: '+schemaId,g.title||'Annotation guideline');W.innerHTML+='<div class="card"><p><span class="badge">'+esc(g.instructions_version)+'</span><span class="badge">'+esc(g.instructions_hash)+'</span></p><h2>Fields</h2>'+g.fields.map(function(f){return'<div class="card"><h3>'+esc(f.label||f.field_id)+'</h3><p>'+esc(f.description||f.help_text||'')+'</p></div>'}).join('')+'<h2>Static examples</h2><ul>'+g.examples.map(function(x){return'<li>'+esc(x)+'</li>'}).join('')+'</ul></div>'}
function collectSchemaFields(){var values={},allowed=null;if(_crItem&&_crItem.form_definition&&Array.isArray(_crItem.form_definition.fields))allowed=new Set(_crItem.form_definition.fields.map(function(field){return field.field_id}));document.querySelectorAll('[data-schema-field]').forEach(function(el){var key=el.dataset.schemaField;if(allowed&&!allowed.has(key))return;if(el.type==='checkbox'){if(!values[key])values[key]=[];if(el.checked)values[key].push(el.value);return}if(el.tagName==='SELECT'&&el.value==='true')values[key]=true;else if(el.tagName==='SELECT'&&el.value==='false')values[key]=false;else if(el.type==='number'&&el.value!=='')values[key]=Number(el.value);else if(el.value!=='')values[key]=el.value});if(_crLabel&&(!allowed||allowed.has('final_label')))values.final_label=_crLabel;return values}
