async function discoverHome(){var d=await api('/api/cases'),domains=await api('/api/domains'),role=(atlasSession.user||{}).role||'reader',primary=role==='owner'?'<a class="button" href="/owner">查看 Pilot 待办</a>':canReview()?'<a class="button" href="/review">继续我的审核</a>':'<a class="button" href="#research-cases">按领域浏览</a>';renderModeNav();var grouped=(domains.items||[]).map(function(domain){var ids=new Set((d.items||[]).filter(function(x){return (x.domain_classification&&x.domain_classification.primary_domain_id||'legacy_unclassified')===domain.domain_id}).map(function(x){return x.case_id}));return'<section class="domain-section"><div class="section-heading"><div><span class="eyebrow">'+esc(CAPABILITY_LABELS[domain.status]||domain.status)+'</span><h2><a href="/domain/'+encodeURIComponent(domain.domain_id)+'">'+esc(domain.label)+'</a></h2><p>'+esc(domain.case_count)+' 个研究问题 · '+esc(domain.dossier_count)+' 个机制档案</p></div></div><div class="case-grid">'+d.items.filter(function(x){return ids.has(x.case_id)}).map(caseCard).join('')+'</div></section>'}).join('');W.innerHTML='<section class="research-hero"><div><span class="eyebrow">机制证据科研工作台</span><h1>理解文献证据为何一致，又为何不同</h1><p>C.O.D.E. Atlas 按 System A 已记录的领域判断组织研究问题；未分类案例保持独立。</p><div class="toolbar">'+primary+'<a class="button secondary" href="/cases">查看全部研究问题</a></div></div></section><section id="research-cases" class="section-heading"><div><span class="eyebrow">领域 → Case → Dossier</span><h2>按领域浏览</h2><p>Primary Domain 决定主分区；Secondary Domain 仅作标签。</p></div><a href="/graph">全局证据地图</a></section>'+grouped+'<section class="activity-section"><h2>最近活动</h2>'+renderLibraryList('recent',5)+'</section>'}
