async function caseDetail(id){var x=await api('/api/case/'+encodeURIComponent(id));rememberRecent({id:x.case_id,label:caseName(x),href:'/case/'+encodeURIComponent(x.case_id)});renderModeNav();W.innerHTML='<nav class="breadcrumbs" aria-label="面包屑"><a href="/discover">研究</a><span>›</span><span>'+esc(caseName(x))+'</span></nav><header class="case-header"><div><span class="eyebrow">研究问题</span><h1>'+esc(caseName(x))+'</h1><p>'+esc(x.research_question)+'</p></div><div class="case-status-stack">'+capabilityBadge('全文证据',x.capabilities.fulltext)+capabilityBadge('实验推理证据链',x.capabilities.reasoning)+capabilityBadge('实验上下文',x.capabilities.context)+'<span class="meta">最后同步 '+esc(x.last_synced_at||'未知')+'</span></div></header><section class="answer-panel"><span class="eyebrow">当前发现</span><h2>'+formalConflictText(x)+'</h2><p>Atlas 收录 '+esc(x.evidence_count)+' 条证据，涉及 '+esc(x.paper_count)+' 篇文献；其中 '+esc(x.non_comparable_records||0)+' 条记录因实验条件不同暂不可直接比较，'+esc(x.weak_candidates||0)+' 条为待核查的弱分歧线索。</p><p class="scientific-boundary">这是对当前已同步证据的确定性状态描述，不是生物学验证结论。</p></section><section><div class="section-heading"><div><span class="eyebrow">关键机制</span><h2>优先阅读的机制证据档案</h2></div><a href="/evidence?case_id='+encodeURIComponent(x.case_id)+'">查看全部</a></div><div class="dossier-grid">'+((x.key_dossiers||[]).map(renderMechanismEvidenceUnit).join('')||'<div class="empty"><h3>暂无可展示机制</h3><p>该案例当前没有进入 Dossier 投影的机制关系。</p></div>')+'</div></section><section><div class="section-heading"><div><span class="eyebrow">实验条件</span><h2>常见上下文</h2><p>仅汇总当前数据中明确提供的字段；未报告值不会被推断补齐。</p></div></div>'+renderContextHighlights(x.common_context)+'</section><section class="secondary-entry"><div><h2>需要查看关系结构？</h2><p>机制图用于局部探索，不替代证据阅读。</p></div><a class="button secondary" href="/graph?case_id='+encodeURIComponent(x.case_id)+'">打开该案例的机制图</a></section>'+renderDeveloperDetails(x,'案例技术详情')}
function renderReasoningTrace(rt){if(rt.status==='artifact_missing'||!rt.items||!rt.items.length)return'<div class="empty reasoning-empty"><h3>实验推理证据链当前不可用</h3><p>'+esc(rt.missing_message||'该运行未生成全文实验推理链。')+'</p><p>Atlas 不会用摘要或其他字段推断补齐。</p></div>';if(rt.status==='produced_but_unusable')return'<div class="empty reasoning-empty"><h3>已生成记录，但尚无可用实验推理步骤</h3><p>'+esc(rt.missing_message)+'</p>'+(isDeveloperMode()?'<p class="meta">技术原因：'+esc(rt.technical_reason||'未报告')+'</p>':'')+'<p>Atlas 不会补写缺失推理。</p></div>';return'<div class="reasoning-list">'+rt.items.map(function(t){var steps=t.steps||[];return'<article class="reasoning-trace"><header><span class="status status-'+esc(t.trace_status||'partial')+'">'+esc(CAPABILITY_LABELS[t.trace_status]||t.trace_status||'状态未知')+'</span><span>来源：'+esc(t.pmid?'PMID '+t.pmid:(t.pmcid||'未报告'))+'</span></header><ol>'+steps.map(function(s,i){var label=s.role||['干预','观察结果','证据作用','作者解释'][i]||('步骤 '+(i+1)),text=s.reported_text||s.text||s.summary||s.evidence_sentence||s.statement||JSON.stringify(s);return'<li><span>'+esc(label)+'</span><p>'+esc(text)+'</p><small>'+esc(s.section_title||s.section||'论文位置未报告')+'</small></li>'}).join('')+'</ol></article>'}).join('')+'</div>'}
function contextTable(ctx,full){var labels={paper_title:'文献',pmid:'PMID',pmcid:'PMCID',case_id:'研究问题',source_scope:'证据来源',section_title:'论文部分',species:'物种',cell_type:'细胞类型',tissue:'组织',disease_or_cancer_type:'疾病/癌种',treatment:'处理',dose:'剂量',time:'时间',duration:'时长',genotype:'基因型',assay_method:'检测方法',direction:'方向',evidence_class:'证据分类',classification_reason:'分类依据'},cols=full?(ctx.columns||[]):(ctx.simple_columns||['paper_title','direction']),rows=ctx.items||[];return'<div class="context-matrix-wrap" tabindex="0"><table class="context-matrix"><thead><tr><th class="compare-col"><span class="sr-only">选择</span></th>'+cols.map(function(c){return'<th>'+esc(labels[c]||c.replaceAll('_',' '))+'</th>'}).join('')+'</tr></thead><tbody>'+rows.map(function(r,i){return'<tr><td class="compare-col"><input type="checkbox" aria-label="选择第 '+(i+1)+' 篇证据进行比较"></td>'+cols.map(function(c){var diff=ctx.summary&&ctx.summary.differing_fields&&ctx.summary.differing_fields[c],prov=r.context_provenance&&r.context_provenance[c];return'<td'+(diff?' data-diff="不同条件"':'')+'>'+(diff?'<span class="cell-label">存在差异</span>':'')+esc(r[c]||'未报告')+(prov?'<small class="provenance">'+esc(prov)+'</small>':'')+'</td>'}).join('')+'</tr>'}).join('')+'</tbody></table></div>'}
