const ROLE_HELP={researcher:'仅浏览领域、案例、证据和机制图。',reviewer:'完成分配给自己的独立审核任务。',adjudicator:'双人审核完成且发生分歧后执行仲裁。',developer:'管理同步、投影与技术诊断；无科研治理权限。',admin:'运营普通用户、Pilot 与任务；不能取代 Owner。',owner:'最高治理权限，包括 Gold、评估、审计和安全管理。',pharma:'旧版只读科研角色。'};
function ownerUserRowRoleAware(x){var roles=['researcher','reviewer','adjudicator','pharma','developer','admin'],roleControl=x.role==='owner'?'<span class="badge">Owner（受保护）</span>':'<select class="owner-role-select" data-role-user="'+esc(x.user_id)+'" aria-label="Role for '+esc(x.username)+'">'+roles.map(function(role){return'<option '+(x.role===role?'selected ':'')+'value="'+role+'">'+role+'</option>'}).join('')+'</select><button class="button-sm" onclick="ownerChangeRole(\''+esc(x.user_id)+'\')">修改角色并撤销旧 Session</button>';return'<tr><td>'+esc(x.username)+'</td><td>'+esc(x.display_name)+'</td><td>'+roleControl+'<small>'+esc(ROLE_HELP[x.role]||'')+'</small></td><td>'+esc(x.status)+'</td><td>'+esc(x.open_assignment_count||0)+'</td><td><button class="button-sm" onclick="ownerToggleUser(\''+esc(x.user_id)+'\','+(!x.enabled)+')">'+(x.enabled?'Disable':'Enable')+'</button><button class="button-sm" onclick="ownerRevokeSessions(\''+esc(x.user_id)+'\')">Revoke sessions</button></td></tr>'}
ownerUsersPage=async function(){var d=await api('/api/owner/users');W.innerHTML='<section class="card"><h2>创建账号</h2><p>Owner 不能通过此表单创建第二个 Owner。高权限角色变更会撤销目标用户旧 Session。</p><div class="secondary-field-grid"><label>Username<input id="ou-username"></label><label>Display name<input id="ou-display"></label><label>Role<select id="ou-role"><option value="researcher">科研阅读者</option><option value="reviewer">Reviewer</option><option value="adjudicator">Adjudicator</option><option value="developer">Developer</option><option value="admin">Admin</option><option value="pharma">药学阅读者（旧版）</option></select></label></div><button class="button" onclick="ownerCreateUser()">创建临时密码账号</button><div id="ou-created"></div><div class="role-help">'+Object.entries(ROLE_HELP).map(function(x){return'<p><strong>'+esc(x[0])+'</strong>：'+esc(x[1])+'</p>'}).join('')+'</div></section><div class="table-scroll"><table><thead><tr><th>用户</th><th>显示名</th><th>角色与影响</th><th>状态</th><th>开放任务</th><th>操作</th></tr></thead><tbody>'+asItems(d).map(ownerUserRowRoleAware).join('')+'</tbody></table></div>'};
ownerInvitesPage=async function(){var d=await api('/api/owner/invites');W.innerHTML='<section class="card"><h2>创建角色化邀请</h2><p>邀请码只显示一次；数据库仅保存 hash。Owner 邀请始终禁止。</p><div class="secondary-field-grid"><label>Label<input id="oi-label"></label><label>Role<select id="oi-role"><option value="researcher">科研阅读者</option><option value="reviewer">Reviewer</option><option value="adjudicator">Adjudicator</option><option value="developer">Developer</option><option value="admin">Admin</option><option value="pharma">药学阅读者（旧版）</option></select></label><label>Max uses<input id="oi-max" type="number" min="1" value="1"></label><label>Notes<input id="oi-notes"></label></div><button class="button" onclick="ownerCreateInvite()">创建邀请</button><div id="oi-created"></div></section><div class="table-scroll"><table><thead><tr><th>Label</th><th>角色</th><th>状态</th><th>使用</th><th>操作</th></tr></thead><tbody>'+asItems(d).map(function(x){return'<tr><td>'+esc(x.label)+'</td><td>'+esc(x.role)+'</td><td>'+esc(x.status)+'</td><td>'+esc(x.uses)+'/'+esc(x.max_uses)+'</td><td><button class="button-sm" onclick="ownerSetInvite(\''+esc(x.invite_id)+'\',false)">Disable</button><button class="button-sm" onclick="ownerSetInvite(\''+esc(x.invite_id)+'\',true)">Enable</button></td></tr>'}).join('')+'</tbody></table></div>'};
const ownerPilotSetupPageBeforeRoles=ownerPilotSetupPage;ownerPilotSetupPage=async function(){await ownerPilotSetupPageBeforeRoles();document.querySelectorAll('#pilot-primary option,#pilot-secondary option').forEach(function(x){if(x.value&&x.textContent.indexOf('(reviewer)')<0)x.remove()});document.querySelectorAll('#pilot-adjudicator option').forEach(function(x){if(x.value&&x.textContent.indexOf('(adjudicator)')<0&&x.textContent.indexOf('(reviewer)')<0)x.remove()})};
// ════════════════ ROUTER ════════════════
function notFoundWorkspace(){title('Page not found','The requested Atlas workspace does not exist.');W.innerHTML+='<div class="empty"><p>Check the address or return to Discover.</p><a class="button" href="/discover">Return to Discover</a></div>'}
async function route(){try{var p=decodeURIComponent(location.pathname),m;if(p==='/'||p==='/discover'||p==='/domains'||p==='/problems')return discoverHome();if(p==='/search')return searchView();if(p==='/library')return libraryWorkspace();if(p==='/account/security')return accountSecurityWorkspace();if((m=p.match(/^\/guidelines\/(.+)$/)))return guidelineWorkspace(m[1]);if(p==='/cases')return caseList();if((m=p.match(/^\/domain\/(.+)$/)))return domainView(m[1]);if((m=p.match(/^\/case\/(.+)$/)))return caseDetail(m[1]);if(p==='/evidence')return evidenceWorkspace();if((m=p.match(/^\/dossier\/(.+)$/)))return dossierView(m[1]);if(p==='/entities')return entities();if((m=p.match(/^\/entity\/(.+)$/)))return entityDetail(m[1]);if(p==='/chains')return chains();if((m=p.match(/^\/chain\/(.+)$/)))return chainPage(m[1]);if(p==='/triples')return evidenceWorkspace();if((m=p.match(/^\/triple\/(.+)$/)))return dossierView(m[1]);if(p==='/graph')return graphView();if(p==='/conflicts')return conflicts();if(p==='/review')return review(false);if(p==='/progress')return progressWorkspace();if(p==='/adjudication')return adjudicationWorkspace();if(p==='/metrics')return review(true);if(p==='/dev'||p==='/console')return devWorkspace();if(p==='/admin'||p.indexOf('/admin/')===0)return adminWorkspace();if(p==='/owner'||p.indexOf('/owner/')===0)return ownerWorkspace();if(p==='/evaluation'||p.indexOf('/evaluation/')===0)return evaluationWorkspace();if(p==='/help')return helpWorkspace();return notFoundWorkspace()}catch(e){console.error('Route error:',e);var heading=e.status===403?'你没有访问此页面的权限':e.status===404?'没有找到该页面或对象':'Unable to load view';W.innerHTML='<div class="error" role="alert"><h2>'+heading+'</h2><p>'+esc(e.message||'Unknown error')+'</p>'+(e.endpoint?'<p class="meta">'+esc(e.endpoint)+(e.status?' · HTTP '+esc(e.status):'')+'</p>':'')+'<div class="toolbar"><a class="button" href="'+esc(atlasSession.landing_path||'/discover')+'">返回自己的工作台</a><a class="button-sm" href="/discover">返回研究首页</a></div></div>'}}

document.addEventListener('keydown',function(e){if(e.key!=='Enter'&&e.key!==' ')return;var graphTarget=e.target&&e.target.closest&&e.target.closest('[data-graph-node-id],[data-graph-edge-id]');if(graphTarget){e.preventDefault();graphTarget.click()}});
// ════════════════ BOOT ════════════════
// ════════════════ EVENT DELEGATION ════════════════
document.addEventListener('click',function(e){var copyEl=e.target.closest('[data-copy-text]');if(copyEl){e.preventDefault();e.stopPropagation();copyTextToClipboard(copyEl.dataset.copyText||"",copyEl);return}var saveEl=e.target.closest('[data-library-save]');if(saveEl){e.preventDefault();saveLibraryItem(saveEl.dataset.librarySave,{object_type:saveEl.dataset.librarySave,stable_id:saveEl.dataset.libraryId,display_title:saveEl.dataset.libraryLabel,view_params:{href:'/dossier/'+encodeURIComponent(saveEl.dataset.libraryId)}});return}var graphEdgeEl=e.target.closest('[data-graph-edge-id]');if(graphEdgeEl){e.preventDefault();selectGraphEdge(graphEdgeEl.dataset.graphEdgeId);return}var graphNodeEl=e.target.closest('[data-graph-node-id][data-graph-neighborhood]');if(graphNodeEl){e.preventDefault();loadGraphNeighborhood(graphNodeEl.dataset.graphNodeId,graphNodeEl.dataset.graphNeighborhood);return}graphNodeEl=e.target.closest('[data-graph-node-id]');if(graphNodeEl){e.preventDefault();selectGraphNode(graphNodeEl.dataset.graphNodeId);return}var pathEl=e.target.closest('[data-path-source][data-path-target]');if(pathEl){e.preventDefault();prefillGraphPath(pathEl.dataset.pathSource,pathEl.dataset.pathTarget);return}var chainEl=e.target.closest('[data-chain-id]');if(chainEl){e.preventDefault();openChain(chainEl.dataset.chainId);return}var tripleEl=e.target.closest('[data-triple-id]');if(tripleEl){e.preventDefault();location.href='/dossier/'+encodeURIComponent(tripleEl.dataset.tripleId);return}});

async function boot(){initModeSwitch();var errors=[];try{atlasSession=await api('/api/session');configureSessionCapabilities(atlasSession)}catch(e){errors.push('Session: '+e.message);atlasSession={csrf_token:'',allowed_workspaces:["discover","library"],debug_access:false};configureSessionCapabilities(atlasSession)}var userEl=document.querySelector('#current-user');if(atlasSession.user){userEl.innerHTML='<span>'+esc(atlasSession.user.display_name)+'</span> <button class="badge logout-button" type="button" onclick="atlasLogout()">Logout</button>'}else{userEl.innerHTML='<span class="muted">Local no-auth mode</span>'};try{var c=await api('/api/cases');cases=c.items;document.querySelector('#case-select').innerHTML+=[...cases].map(function(x){return'<option value="'+esc(x.case_id)+'">'+esc(x.case_id)+'</option>'}).join('')}catch(e){errors.push('Cases: '+e.message);cases=[]};document.querySelector('#case-select').onchange=function(e){if(e.target.value)location.href='/case/'+encodeURIComponent(e.target.value)};document.querySelector('#global-search').placeholder='搜索药物、基因、蛋白、通路、疾病、研究问题或 PMID';document.querySelector('#global-search').onkeydown=function(e){if(e.key==='Enter')location.href='/search?q='+encodeURIComponent(e.target.value)};document.addEventListener('keydown',function(e){if((e.ctrlKey||e.metaKey)&&e.key.toLowerCase()==='k'){e.preventDefault();document.querySelector('#global-search').focus()}});if(errors.length>0){var banner=document.createElement('div');banner.className='error-banner';banner.innerHTML='<strong>Startup warnings:</strong> '+errors.map(esc).join('; ')+' <button class=\"button-sm\" onclick=\"this.parentElement.remove()\">Dismiss</button>';document.querySelector('header').after(banner)};await route()}boot().catch(function(e){W.innerHTML='<div class="error">'+esc(e.message)+'</div>'});
